const SKILLS = [{"slug": "accessibility-basic-auditor", "name": "Accessibility Basic Auditor", "category": "Accesibilidad", "tags": ["a11y", "teclado", "contraste"], "priority": "Media", "description": "Audita accesibilidad básica de apps web: contraste, teclado, foco, labels, semántica HTML, aria y legibilidad móvil.", "whenToUse": "El usuario quiere que una app sea más profesional, usable, móvil, seria, o apta para personas mayores o usuarios no técnicos.", "useCase": "Cuando quieres revisar teclado, contraste, labels, foco y accesibilidad mínima.", "command": "/accessibility-basic-auditor", "example": "/accessibility-basic-auditor revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Accessibility Basic Auditor\ndescription: Audita accesibilidad básica de apps web: contraste, teclado, foco, labels, semántica HTML, aria y legibilidad móvil.\nwhen_to_use: El usuario quiere que una app sea más profesional, usable, móvil, seria, o apta para personas mayores o usuarios no técnicos.\nargument-hint: [tipo de interfaz]\n---\n\n# Accessibility Basic Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de accesibilidad pragmática para frontend.\n\n## Revisión mínima\n1. Estructura: `main`, `header`, `button`, `label`, headings correctos.\n2. Teclado: tabulación lógica, foco visible, botones reales.\n3. Formularios: labels asociados y errores comprensibles.\n4. Contraste y tamaño de texto.\n5. Estados: loading, error, vacío, éxito.\n6. ARIA solo cuando aporte; no tapar HTML malo con ARIA.\n7. Personas mayores: botones grandes, confirmaciones y lenguaje claro.\n\n## Salida\nDa:\n- Problemas prioritarios.\n- Cambios HTML/CSS concretos.\n- Checklist rápida con teclado y móvil.\n", "bytes": 1010}, {"slug": "ai-feature-designer", "name": "AI Feature Designer", "category": "IA / Producto", "tags": ["ia", "mvp", "producto", "ollama"], "priority": "Media", "description": "Decide si una app necesita IA real, motor local, simulación, plantillas, API externa u Ollama para aportar valor sin complicarla.", "whenToUse": "Úsalo cuando el usuario pregunta “¿le metemos IA?”, “¿hace falta pagar API?”, “¿puede ser local?” o quiere una función inteligente.", "useCase": "Úsalo cuando el usuario pregunta “¿le metemos IA?”, “¿hace falta pagar API?”, “¿puede ser local?” o quiere una función inteligente.", "command": "/ai-feature-designer", "example": "/ai-feature-designer revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: AI Feature Designer\ndescription: Decide si una app necesita IA real, motor local, simulación, plantillas, API externa u Ollama para aportar valor sin complicarla.\nwhen_to_use: Úsalo cuando el usuario pregunta “¿le metemos IA?”, “¿hace falta pagar API?”, “¿puede ser local?” o quiere una función inteligente.\nargument-hint: [idea de función IA]\n---\n\n# AI Feature Designer\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como diseñador de producto IA pragmático.\n\n## Comparación obligatoria\nPara cada función propuesta compara:\n1. Motor local basado en reglas.\n2. Plantillas y heurísticas sin IA.\n3. IA externa con clave del usuario.\n4. Ollama local.\n5. Backend SaaS.\n\n## Criterios\n- Valor real para el usuario.\n- Coste y fricción.\n- Privacidad.\n- Mantenimiento.\n- Riesgo de prometer demasiado.\n- Qué pasa si la IA falla.\n\n## Salida\nEntrega:\n- Si conviene IA o no.\n- Mejor arquitectura.\n- MVP mínimo.\n- Prompt o motor local inicial.\n- Riesgos y límites claros.\n", "bytes": 987}, {"slug": "ai-integration-planner", "name": "AI Integration Planner", "category": "IA / Producto", "tags": ["api", "ollama", "claves", "ia"], "priority": "Media", "description": "Diseña integración de IA en apps locales o web: API key del usuario, Ollama local, modo sin IA, privacidad, costes y arquitectura seria.", "whenToUse": "El usuario pregunta si añadir IA, API keys de OpenAI/Claude/Gemini, Ollama, modo local, SaaS, claves del usuario, o cómo hacer un producto serio con IA.", "useCase": "Cuando quieres meter IA con API key del usuario, Ollama o modo manual sin exponer claves.", "command": "/ai-integration-planner", "example": "/ai-integration-planner revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: AI Integration Planner\ndescription: Diseña integración de IA en apps locales o web: API key del usuario, Ollama local, modo sin IA, privacidad, costes y arquitectura seria.\nwhen_to_use: El usuario pregunta si añadir IA, API keys de OpenAI/Claude/Gemini, Ollama, modo local, SaaS, claves del usuario, o cómo hacer un producto serio con IA.\nargument-hint: [objetivo opcional]\n---\n\n# AI Integration Planner\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como arquitecto de producto IA. Diseña una integración realista, segura y mantenible.\n\n## Opciones a comparar siempre\n1. Sin IA: motor local basado en reglas, plantillas y heurísticas.\n2. API externa con clave del usuario.\n3. Backend propio con claves protegidas.\n4. Ollama/localhost para privacidad.\n5. SaaS completo con login, base de datos, billing y panel admin.\n\n## Revisión de seguridad\n- Nunca meter claves privadas en frontend público.\n- Si la clave la introduce el usuario:\n  - Explicar dónde se guarda.\n  - Permitir borrarla.\n  - No enviarla a terceros salvo al proveedor elegido.\n  - Advertir costes.\n- Separar claramente modo demo, modo local y modo API real.\n\n## Salida\nEntrega:\n- Mejor opción para el caso.\n- Arquitectura mínima.\n- Flujo de usuario.\n- Riesgos.\n- Primer MVP realista.\n- Evolución a producto serio.\n", "bytes": 1294}, {"slug": "api-key-safety-planner", "name": "API Key Safety Planner", "category": "IA / Seguridad", "tags": ["api key", "seguridad", "costes", "privacidad"], "priority": "Alta", "description": "Diseña manejo seguro de claves API introducidas por el usuario: almacenamiento, borrado, avisos, costes, límites y arquitectura.", "whenToUse": "Úsalo cuando una app web quiere usar OpenAI, Claude, Gemini u otra API con una clave que pondrá cada usuario.", "useCase": "Úsalo cuando una app web quiere usar OpenAI, Claude, Gemini u otra API con una clave que pondrá cada usuario.", "command": "/api-key-safety-planner", "example": "/api-key-safety-planner revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: API Key Safety Planner\ndescription: Diseña manejo seguro de claves API introducidas por el usuario: almacenamiento, borrado, avisos, costes, límites y arquitectura.\nwhen_to_use: Úsalo cuando una app web quiere usar OpenAI, Claude, Gemini u otra API con una clave que pondrá cada usuario.\nargument-hint: [proveedor API y tipo de app]\n---\n\n# API Key Safety Planner\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como arquitecto de seguridad para apps con API keys del usuario.\n\n## Reglas\n1. Nunca hardcodear claves privadas en frontend público.\n2. Si el usuario introduce su clave, explicar dónde se guarda.\n3. Permitir ver estado, cambiar y borrar la clave.\n4. Usar `sessionStorage` o memoria si la privacidad pesa más que comodidad.\n5. Usar `localStorage` solo con aviso claro y botón de borrado.\n6. Advertir que la clave puede generar costes.\n7. No enviar la clave a ningún sitio salvo al proveedor elegido.\n8. Si hay backend propio, la clave debe vivir en servidor, no en el navegador.\n\n## Salida\nEntrega:\n- Arquitectura recomendada.\n- Riesgos.\n- Textos de aviso al usuario.\n- Flujo de guardar/borrar clave.\n- Checklist de publicación.\n", "bytes": 1149}, {"slug": "app-product-polisher", "name": "App Product Polisher", "category": "Producto", "tags": ["ux", "microcopy", "onboarding", "producto"], "priority": "Media", "description": "Convierte una app funcional en producto presentable: onboarding, microcopy, estados vacíos, mensajes, flujo y sensación profesional.", "whenToUse": "Úsalo cuando la app ya funciona pero parece prototipo, tiene textos feos, estados vacíos pobres, botones confusos o falta sensación de producto serio.", "useCase": "Úsalo cuando la app ya funciona pero parece prototipo, tiene textos feos, estados vacíos pobres, botones confusos o falta sensación de producto serio.", "command": "/app-product-polisher", "example": "/app-product-polisher revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: App Product Polisher\ndescription: Convierte una app funcional en producto presentable: onboarding, microcopy, estados vacíos, mensajes, flujo y sensación profesional.\nwhen_to_use: Úsalo cuando la app ya funciona pero parece prototipo, tiene textos feos, estados vacíos pobres, botones confusos o falta sensación de producto serio.\nargument-hint: [objetivo de pulido]\n---\n\n# App Product Polisher\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como product designer y editor de microcopy.\n\n## Revisión\n1. Primera impresión: título, promesa, subtítulo y acción principal.\n2. Onboarding: el usuario debe entender qué hacer en 10 segundos.\n3. Estados vacíos: deben guiar, no parecer error.\n4. Estados de carga/error/éxito: claros y humanos.\n5. Microcopy: botones concretos, sin jerga técnica innecesaria.\n6. Confianza: privacidad, límites, advertencias y expectativas.\n7. Detalles finales: textos provisionales, etiquetas raras, placeholders pobres.\n\n## Salida\nEntrega:\n- Diagnóstico de producto.\n- Textos concretos mejorados.\n- Cambios de UX prioritarios.\n- Checklist de pulido final.\n", "bytes": 1098}, {"slug": "brand-voice-dark", "name": "Brand Voice Dark", "category": "Marca / Creativo", "tags": ["marca", "voz", "oscuro"], "priority": "Media", "description": "Mantiene una voz de marca oscura, elegante y coherente para webs de autor, apps góticas, copy promocional y proyectos creativos.", "whenToUse": "El usuario trabaja en webs de autor, novelas, apps oscuras, estética gótica/VHS/Lovecraft/Carpenter, copy de landing, títulos o textos de producto con identidad propia.", "useCase": "Cuando quieres mantener una voz oscura, elegante y reconocible en webs, apps o textos.", "command": "/brand-voice-dark", "example": "/brand-voice-dark revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Brand Voice Dark\ndescription: Mantiene una voz de marca oscura, elegante y coherente para webs de autor, apps góticas, copy promocional y proyectos creativos.\nwhen_to_use: El usuario trabaja en webs de autor, novelas, apps oscuras, estética gótica/VHS/Lovecraft/Carpenter, copy de landing, títulos o textos de producto con identidad propia.\nargument-hint: [objetivo opcional]\n---\n\n# Brand Voice Dark\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como director de voz de marca para proyectos oscuros, literarios y tecnológicos.\n\n## Identidad\n- Sobria.\n- Oscura sin caer en parodia.\n- Cinematográfica pero clara.\n- Misteriosa, no confusa.\n- Elegante, no adolescente.\n- Con tensión, no exageración.\n\n## Reglas\n- Evita frases genéricas tipo “adéntrate en un mundo...” salvo que estén muy justificadas.\n- Evita exceso de adjetivos oscuros acumulados.\n- Prioriza imagen concreta sobre abstracción.\n- Mantén coherencia entre título, subtítulo, botones y descripciones.\n- Si es una app útil, no la entierres bajo estética.\n\n## Salida\nDevuelve:\n- Versión actual criticada.\n- Versión mejorada.\n- Variante más comercial.\n- Variante más literaria.\n- Motivo de los cambios.\n", "bytes": 1189}, {"slug": "browser-compatibility-auditor", "name": "Browser Compatibility Auditor", "category": "Compatibilidad", "tags": ["chrome", "firefox", "edge", "safari"], "priority": "Alta", "description": "Revisa compatibilidad entre Chrome, Edge, Firefox y Safari: APIs, CSS moderno, módulos, PWA, clipboard, audio y fallbacks.", "whenToUse": "Úsalo cuando una app debe funcionar en varios navegadores o falla fuera de Chrome.", "useCase": "Úsalo cuando una app debe funcionar en varios navegadores o falla fuera de Chrome.", "command": "/browser-compatibility-auditor", "example": "/browser-compatibility-auditor revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Browser Compatibility Auditor\ndescription: Revisa compatibilidad entre Chrome, Edge, Firefox y Safari: APIs, CSS moderno, módulos, PWA, clipboard, audio y fallbacks.\nwhen_to_use: Úsalo cuando una app debe funcionar en varios navegadores o falla fuera de Chrome.\nargument-hint: [navegadores objetivo]\n---\n\n# Browser Compatibility Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de compatibilidad web.\n\n## Revisión obligatoria\n1. JavaScript: módulos, optional chaining, APIs modernas y polyfills necesarios.\n2. CSS: `:has`, `backdrop-filter`, `dvh`, grid/flex, safe areas y soporte móvil.\n3. APIs del navegador: Clipboard, Share, Audio, Notifications, Speech, File APIs, Service Worker.\n4. PWA: diferencias entre Chrome/Edge y Safari/iOS.\n5. Fallbacks: qué mostrar cuando una API no existe.\n6. Degradación elegante: la función crítica debe seguir siendo usable.\n\n## Salida\nEntrega:\n- Tabla navegador/riesgo.\n- APIs sospechosas.\n- Fallbacks concretos.\n- Pruebas manuales por navegador.\n", "bytes": 1013}, {"slug": "claude-skill-builder", "name": "Claude Skill Builder", "category": "Skills", "tags": ["crear skills", "claude code"], "priority": "Media", "description": "Convierte un prompt repetido o flujo de trabajo en una Skill de Claude Code con SKILL.md, descripción, criterios de uso, checklist y ejemplos.", "whenToUse": "El usuario quiere crear nuevas Claude Skills, empaquetar prompts, automatizar un método repetido o convertir una chuleta en una skill instalable.", "useCase": "Cuando quieres crear una nueva Skill con estructura limpia y reusable.", "command": "/claude-skill-builder", "example": "/claude-skill-builder revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Claude Skill Builder\ndescription: Convierte un prompt repetido o flujo de trabajo en una Skill de Claude Code con SKILL.md, descripción, criterios de uso, checklist y ejemplos.\nwhen_to_use: El usuario quiere crear nuevas Claude Skills, empaquetar prompts, automatizar un método repetido o convertir una chuleta en una skill instalable.\nargument-hint: [objetivo de la skill]\n---\n\n# Claude Skill Builder\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como diseñador de Skills para Claude Code.\n\n## Proceso\n1. Detecta la tarea repetible.\n2. Define nombre de carpeta en kebab-case.\n3. Escribe `description` clara: qué hace y cuándo usarla.\n4. Añade `when_to_use` con disparadores reales.\n5. Crea instrucciones cortas, verificables y accionables.\n6. Añade formato de salida obligatorio.\n7. Si la Skill es compleja, propone archivos de apoyo: `examples.md`, `checklist.md`, `templates/` o `scripts/`.\n8. Evita que el `SKILL.md` sea enorme.\n\n## Salida\nEntrega:\n- Nombre de carpeta.\n- `SKILL.md` completo.\n- Archivos de apoyo recomendados.\n- Prueba de invocación.\n", "bytes": 1065}, {"slug": "codebase-context-loader", "name": "Codebase Context Loader", "category": "Contexto", "tags": ["repo", "arquitectura", "estructura"], "priority": "Alta", "description": "Carga contexto técnico de un repositorio antes de auditar o modificar: estructura, archivos clave, package.json, manifest, service worker y estado Git.", "whenToUse": "Úsalo antes de revisar una app, depurar un bug, preparar una release o pedir cambios sobre un proyecto con varios archivos.", "useCase": "Antes de auditar: obliga a Claude a entender estructura, archivos y flujo antes de opinar.", "command": "/codebase-context-loader", "example": "/codebase-context-loader revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Codebase Context Loader\ndescription: Carga contexto técnico de un repositorio antes de auditar o modificar: estructura, archivos clave, package.json, manifest, service worker y estado Git.\nwhen_to_use: Úsalo antes de revisar una app, depurar un bug, preparar una release o pedir cambios sobre un proyecto con varios archivos.\nargument-hint: [objetivo de análisis]\n---\n\n# Codebase Context Loader\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como explorador técnico del proyecto. Tu objetivo es entender el repo antes de opinar o tocar código.\n\n## Proceso obligatorio\n1. Identifica la raíz del proyecto.\n2. Lista archivos y carpetas relevantes, ignorando `node_modules`, `.git`, `dist`, `build` y backups.\n3. Detecta stack: HTML suelto, PWA, Vite, React, Electron, Node, etc.\n4. Localiza puntos de entrada: `index.html`, `app.js`, `main.js`, `package.json`, `manifest.json`, `sw.js`.\n5. Resume qué hace la app según código y README, no por suposiciones.\n6. Si hay Git, revisa estado y archivos modificados.\n\n## Comandos sugeridos si están disponibles\n- `pwd`\n- `git status --short`\n- `git ls-files`\n- `find . -maxdepth 3 -type f | sort`\n- `cat package.json`\n\n## Salida\nEntrega:\n- Tipo de proyecto.\n- Archivos clave.\n- Flujo principal probable.\n- Riesgos iniciales.\n- Qué Skill conviene invocar después.\n", "bytes": 1316}, {"slug": "console-error-hunter", "name": "Console Error Hunter", "category": "Debugging", "tags": ["consola", "javascript", "promesas", "errores"], "priority": "Alta", "description": "Localiza errores de consola, promesas rotas, eventos duplicados, fallos silenciosos y bloqueos JavaScript en apps web.", "whenToUse": "Úsalo cuando una app carga pero algo no responde, aparece un error rojo en consola, una promesa falla, un botón no ejecuta o una función queda bloqueada.", "useCase": "Úsalo cuando una app carga pero algo no responde, aparece un error rojo en consola, una promesa falla, un botón no ejecuta o una función queda bloqueada.", "command": "/console-error-hunter", "example": "/console-error-hunter revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Console Error Hunter\ndescription: Localiza errores de consola, promesas rotas, eventos duplicados, fallos silenciosos y bloqueos JavaScript en apps web.\nwhen_to_use: Úsalo cuando una app carga pero algo no responde, aparece un error rojo en consola, una promesa falla, un botón no ejecuta o una función queda bloqueada.\nargument-hint: [síntoma o error de consola]\n---\n\n# Console Error Hunter\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como cazador de errores de consola y fallos silenciosos en JavaScript.\n\n## Proceso obligatorio\n1. Revisa el síntoma exacto y el flujo que lo dispara.\n2. Pide o inspecciona los errores de consola si están disponibles.\n3. Localiza funciones con `addEventListener`, `async/await`, `Promise`, `try/catch`, `setTimeout`, estados globales y manipulación DOM.\n4. Busca estos patrones:\n   - variables no definidas;\n   - selectores que devuelven `null`;\n   - listeners duplicados;\n   - promesas sin `catch` o sin `finally`;\n   - estado `busy`, `loading` o `typing` que no se libera;\n   - `innerHTML` que borra nodos con listeners;\n   - errores tragados por `catch` vacío.\n5. Propón la corrección mínima y una prueba de regresión.\n\n## Salida\nEntrega:\n- Error o fallo probable.\n- Archivo y función sospechosa.\n- Causa raíz.\n- Corrección exacta.\n- Prueba manual para confirmar.\n", "bytes": 1321}, {"slug": "dark-landing-page-writer", "name": "Dark Landing Page Writer", "category": "Marca / Creativo", "tags": ["landing", "copy", "oscuro", "cta"], "priority": "Media", "description": "Escribe landing pages oscuras, elegantes y comerciales para apps, webs de autor, herramientas creativas o productos con atmósfera.", "whenToUse": "Úsalo cuando el proyecto necesita copy de portada, hero, beneficios, CTA, secciones, tono oscuro y venta sin sonar exagerado.", "useCase": "Úsalo cuando el proyecto necesita copy de portada, hero, beneficios, CTA, secciones, tono oscuro y venta sin sonar exagerado.", "command": "/dark-landing-page-writer", "example": "/dark-landing-page-writer revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Dark Landing Page Writer\ndescription: Escribe landing pages oscuras, elegantes y comerciales para apps, webs de autor, herramientas creativas o productos con atmósfera.\nwhen_to_use: Úsalo cuando el proyecto necesita copy de portada, hero, beneficios, CTA, secciones, tono oscuro y venta sin sonar exagerado.\nargument-hint: [producto o app]\n---\n\n# Dark Landing Page Writer\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como copywriter de landing pages con tono oscuro, sobrio y comercial.\n\n## Objetivo\nVender o presentar el proyecto sin caer en frases vacías ni estética adolescente.\n\n## Estructura\n1. Hero: título, subtítulo y CTA principal.\n2. Problema que resuelve.\n3. Beneficios concretos.\n4. Cómo funciona.\n5. Privacidad/límites si aplica.\n6. Sección de confianza.\n7. CTA final.\n\n## Reglas de voz\n- Oscuro no significa confuso.\n- Elegante antes que recargado.\n- Concreto antes que grandilocuente.\n- Si es una herramienta, que se entienda su utilidad.\n\n## Salida\nEntrega:\n- Versión completa de landing.\n- Variante más comercial.\n- Variante más literaria.\n- Botones y microcopy.\n", "bytes": 1095}, {"slug": "fiction-world-bible-builder", "name": "Fiction World Bible Builder", "category": "Narrativa", "tags": ["biblia", "novela", "worldbuilding", "estructura"], "priority": "Media", "description": "Construye biblias narrativas: premisa, reglas de mundo, personajes, conflicto, tono, mapa de capítulos y coherencia interna.", "whenToUse": "Úsalo para novelas, universos de ficción, horror, thriller, fantasía oscura o proyectos narrativos que necesitan arquitectura antes de escribir.", "useCase": "Úsalo para novelas, universos de ficción, horror, thriller, fantasía oscura o proyectos narrativos que necesitan arquitectura antes de escribir.", "command": "/fiction-world-bible-builder", "example": "/fiction-world-bible-builder revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Fiction World Bible Builder\ndescription: Construye biblias narrativas: premisa, reglas de mundo, personajes, conflicto, tono, mapa de capítulos y coherencia interna.\nwhen_to_use: Úsalo para novelas, universos de ficción, horror, thriller, fantasía oscura o proyectos narrativos que necesitan arquitectura antes de escribir.\nargument-hint: [premisa o universo]\n---\n\n# Fiction World Bible Builder\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como arquitecto narrativo y editor de continuidad.\n\n## Proceso\n1. Define premisa nuclear en una frase.\n2. Establece reglas del mundo y límites.\n3. Diseña conflicto central y amenaza progresiva.\n4. Crea personajes con deseo, herida, contradicción y función dramática.\n5. Define tono, atmósfera y prohibiciones de estilo.\n6. Mapea actos, capítulos o bloques.\n7. Detecta clichés, incoherencias y repeticiones.\n8. No escribas escenas completas salvo que se pida.\n\n## Salida\nEntrega:\n- ADN narrativo.\n- Reglas del mundo.\n- Personajes principales.\n- Estructura por actos.\n- Riesgos creativos.\n- Siguiente paso recomendado.\n", "bytes": 1072}, {"slug": "github-app-auditor", "name": "GitHub App Auditor", "category": "Apps / GitHub", "tags": ["github", "frontend", "html", "js", "auditoría"], "priority": "Alta", "description": "Audita apps HTML/CSS/JavaScript, PWAs o proyectos frontend antes de subirlos a GitHub/GitHub Pages. Úsalo para revisar si una app local está lista, si falla, si parece profesional o si hay bugs.", "whenToUse": "El usuario pide revisar una app, preparar un proyecto para GitHub, comprobar si está lista, detectar fallos, mejorar HTML/CSS/JS, GitHub Pages, zip final, versión definitiva, PWA o app local.", "useCase": "Cuando tienes una app HTML/CSS/JS y quieres saber si ya está lista para GitHub o si tiene fallos ocultos.", "command": "/github-app-auditor", "example": "/github-app-auditor revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: GitHub App Auditor\ndescription: Audita apps HTML/CSS/JavaScript, PWAs o proyectos frontend antes de subirlos a GitHub/GitHub Pages. Úsalo para revisar si una app local está lista, si falla, si parece profesional o si hay bugs.\nwhen_to_use: El usuario pide revisar una app, preparar un proyecto para GitHub, comprobar si está lista, detectar fallos, mejorar HTML/CSS/JS, GitHub Pages, zip final, versión definitiva, PWA o app local.\nargument-hint: [objetivo opcional]\n---\n\n# GitHub App Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como arquitecto senior frontend y auditor de producto. Tu objetivo es convertir una app local o web sencilla en un proyecto serio, fiable y presentable para GitHub.\n\n## Proceso\n1. Inspecciona la estructura del proyecto antes de opinar.\n2. Identifica el tipo de app: HTML suelto, PWA, Vite, React, Electron, Node, etc.\n3. Revisa funcionalidad real, no solo apariencia.\n4. Comprueba estos puntos:\n   - Arranque local.\n   - GitHub Pages compatible.\n   - Errores de consola.\n   - HTML válido y semántico.\n   - CSS responsive.\n   - JavaScript sin bloqueos ni estados rotos.\n   - Safari/iPhone cuando aplique.\n   - Accesibilidad básica.\n   - Persistencia local si usa localStorage.\n   - README, LICENSE, SECURITY, CHANGELOG y .gitignore.\n5. Si hay bugs, prioriza arreglarlos antes de añadir funciones.\n6. Si el usuario pide “versión final”, exige una verificación final.\n\n## Criterio duro\n- No confundas “bonito” con “funciona”.\n- No declares “100%” sin pruebas.\n- Si falta una prueba manual, dilo.\n- Si algo es innecesario para GitHub, elimínalo.\n- Si hay archivos duplicados o nombres raros, normaliza.\n\n## Formato de respuesta obligatorio\nResponde siempre con:\n1. Veredicto directo.\n2. Hallazgos priorizados: Crítico, Alto, Medio, Bajo.\n3. Cambios concretos por archivo o sección.\n4. Plan de acción mínimo para dejarlo listo.\n5. Checklist final de verificación.\n\nNo digas que algo está listo si no has revisado pruebas, errores de consola, responsive, accesibilidad básica y seguridad mínima.\n\n\n## Evidencia mínima antes del veredicto\nAntes de decir que algo está listo, intenta obtener evidencia del proyecto real: estructura de archivos, puntos de entrada, errores visibles, flujo principal y pruebas reproducibles. Si no puedes ejecutar o abrir la app, dilo como limitación y da una checklist manual.\n", "bytes": 2381}, {"slug": "github-pages-deploy-check", "name": "GitHub Pages Deploy Check", "category": "GitHub Pages", "tags": ["deploy", "pages", "rutas"], "priority": "Alta", "description": "Comprueba si un proyecto web está preparado para publicarse en GitHub Pages: rutas relativas, assets, manifest, service worker, base path y README.", "whenToUse": "El usuario quiere subir una app a GitHub Pages, dice que en local funciona pero en GitHub no, o pide preparar un zip final publicable.", "useCase": "Cuando una app falla al subirla a GitHub Pages por rutas, assets, service worker o base path.", "command": "/github-pages-deploy-check", "example": "/github-pages-deploy-check revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: GitHub Pages Deploy Check\ndescription: Comprueba si un proyecto web está preparado para publicarse en GitHub Pages: rutas relativas, assets, manifest, service worker, base path y README.\nwhen_to_use: El usuario quiere subir una app a GitHub Pages, dice que en local funciona pero en GitHub no, o pide preparar un zip final publicable.\nargument-hint: [nombre repo opcional]\n---\n\n# GitHub Pages Deploy Check\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de despliegue GitHub Pages.\n\n## Revisión obligatoria\n1. `index.html` existe en raíz o carpeta de publicación.\n2. Todas las rutas son relativas o compatibles con subcarpeta de repo.\n3. No hay referencias a archivos locales inexistentes.\n4. `manifest.json` usa `start_url` y `scope` compatibles.\n5. `sw.js` no rompe la app al estar bajo `/nombre-repo/`.\n6. Assets, iconos, CSS y JS tienen nombres correctos y coinciden en mayúsculas/minúsculas.\n7. No se suben claves, zips de trabajo, copias duplicadas ni datos reales.\n8. README explica cómo activar Pages.\n\n## Salida\nDa:\n- Estado: listo / casi listo / no listo.\n- Errores que romperían GitHub Pages.\n- Cambios exactos.\n- Pasos para publicar.\n- Prueba final en URL pública.\n", "bytes": 1199}, {"slug": "github-pages-path-fixer", "name": "GitHub Pages Path Fixer", "category": "GitHub Pages", "tags": ["rutas", "assets", "pages", "subcarpeta"], "priority": "Alta", "description": "Corrige rutas relativas, assets rotos, manifest, iconos, service worker y enlaces que fallan al publicar en GitHub Pages.", "whenToUse": "Úsalo cuando una app funciona en local pero falla en GitHub Pages, no carga CSS/JS, no aparecen imágenes, no registra PWA o los enlaces apuntan mal.", "useCase": "Úsalo cuando una app funciona en local pero falla en GitHub Pages, no carga CSS/JS, no aparecen imágenes, no registra PWA o los enlaces apuntan mal.", "command": "/github-pages-path-fixer", "example": "/github-pages-path-fixer revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: GitHub Pages Path Fixer\ndescription: Corrige rutas relativas, assets rotos, manifest, iconos, service worker y enlaces que fallan al publicar en GitHub Pages.\nwhen_to_use: Úsalo cuando una app funciona en local pero falla en GitHub Pages, no carga CSS/JS, no aparecen imágenes, no registra PWA o los enlaces apuntan mal.\nargument-hint: [URL o estructura del repo]\n---\n\n# GitHub Pages Path Fixer\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como especialista en despliegue de apps estáticas en GitHub Pages.\n\n## Revisión obligatoria\n1. Detecta si el proyecto se publica en raíz o subcarpeta del usuario/repo.\n2. Cambia rutas absolutas incorrectas (`/style.css`) por rutas relativas (`./style.css`) cuando proceda.\n3. Revisa `manifest.json`: `start_url`, `scope`, iconos y rutas.\n4. Revisa `sw.js`: cache, rutas, versionado y fallback.\n5. Comprueba enlaces internos, descargas, imágenes, fuentes, audio y assets.\n6. Evita dependencias externas si la app promete offline.\n7. Da pasos concretos para Settings → Pages.\n\n## Salida\nEntrega:\n- Lista de rutas sospechosas.\n- Cambios por archivo.\n- Prueba local con servidor.\n- Prueba final en URL pública.\n", "bytes": 1159}, {"slug": "kdp-launch-checklist", "name": "KDP Launch Checklist", "category": "KDP / Publicación", "tags": ["kdp", "amazon", "publicación", "novela"], "priority": "Media", "description": "Checklist de lanzamiento KDP: manuscrito, portada, descripción, categorías, keywords, precio, metadatos, prueba final y plan de publicación.", "whenToUse": "Úsalo cuando una novela o libro va a publicarse en Amazon KDP o necesita revisión previa de lanzamiento.", "useCase": "Úsalo cuando una novela o libro va a publicarse en Amazon KDP o necesita revisión previa de lanzamiento.", "command": "/kdp-launch-checklist", "example": "/kdp-launch-checklist revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: KDP Launch Checklist\ndescription: Checklist de lanzamiento KDP: manuscrito, portada, descripción, categorías, keywords, precio, metadatos, prueba final y plan de publicación.\nwhen_to_use: Úsalo cuando una novela o libro va a publicarse en Amazon KDP o necesita revisión previa de lanzamiento.\nargument-hint: [título o estado del libro]\n---\n\n# KDP Launch Checklist\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como responsable de lanzamiento editorial para KDP.\n\n## Checklist\n1. Manuscrito: versión final, ortografía, formato, índice y metadatos internos.\n2. Portada: legibilidad en miniatura, género claro, autor visible, contraste.\n3. Descripción: gancho, conflicto, tono y CTA sin spoilers excesivos.\n4. Categorías y keywords: coherencia con género y lector objetivo.\n5. Precio y territorios.\n6. Vista previa Kindle: saltos, capítulos, portada, tipografías.\n7. Página de autor y enlaces.\n8. Plan de lanzamiento: fecha, redes, beta readers, reseñas permitidas y seguimiento.\n\n## Salida\nEntrega:\n- Estado de publicación.\n- Riesgos antes de subir.\n- Checklist por prioridad.\n- Texto de descripción mejorado si se proporciona.\n", "bytes": 1147}, {"slug": "local-first-architecture", "name": "Local First Architecture", "category": "Arquitectura Local", "tags": ["local-first", "offline", "privacidad", "portable"], "priority": "Alta", "description": "Diseña o audita apps local-first: offline, portables, sin servidor obligatorio, con datos del usuario bajo su control.", "whenToUse": "Úsalo para apps que deben funcionar abriendo index.html, sin internet, sin servidor, con privacidad y persistencia local.", "useCase": "Úsalo para apps que deben funcionar abriendo index.html, sin internet, sin servidor, con privacidad y persistencia local.", "command": "/local-first-architecture", "example": "/local-first-architecture revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Local First Architecture\ndescription: Diseña o audita apps local-first: offline, portables, sin servidor obligatorio, con datos del usuario bajo su control.\nwhen_to_use: Úsalo para apps que deben funcionar abriendo index.html, sin internet, sin servidor, con privacidad y persistencia local.\nargument-hint: [tipo de app local]\n---\n\n# Local First Architecture\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como arquitecto local-first y offline-first.\n\n## Principios\n1. La app debe funcionar sin login ni servidor salvo que sea imprescindible.\n2. Los datos deben estar bajo control del usuario.\n3. Debe existir exportación, importación y borrado cuando haya datos persistentes.\n4. El modo offline debe ser real, no solo un eslogan.\n5. Los errores de red no deben romper el flujo principal.\n6. Si hay IA, separar modo local, modo API externa y modo manual.\n\n## Revisión\n- Persistencia: localStorage, IndexedDB o archivos exportables.\n- Portabilidad: ZIP, GitHub Pages, uso local.\n- Privacidad: datos guardados y avisos.\n- Resiliencia: carga sin conexión, fallback, recuperación.\n\n## Salida\nEntrega:\n- Arquitectura recomendada.\n- Qué guardar y dónde.\n- Riesgos.\n- Plan MVP.\n- Evolución profesional.\n", "bytes": 1207}, {"slug": "local-storage-data-auditor", "name": "Local Storage Data Auditor", "category": "Datos Locales", "tags": ["localStorage", "datos", "exportar"], "priority": "Media", "description": "Audita datos guardados en localStorage/sessionStorage/IndexedDB: privacidad, borrado, migraciones, tamaño, seguridad y UX.", "whenToUse": "El usuario trabaja con historial local, diario, claves API del usuario, apps offline, datos sensibles, privacidad o borrado de información.", "useCase": "Cuando la app guarda historial, notas, claves o datos privados en el navegador.", "command": "/local-storage-data-auditor", "example": "/local-storage-data-auditor revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Local Storage Data Auditor\ndescription: Audita datos guardados en localStorage/sessionStorage/IndexedDB: privacidad, borrado, migraciones, tamaño, seguridad y UX.\nwhen_to_use: El usuario trabaja con historial local, diario, claves API del usuario, apps offline, datos sensibles, privacidad o borrado de información.\nargument-hint: [datos que guarda la app]\n---\n\n# Local Storage Data Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de almacenamiento local.\n\n## Revisión obligatoria\n1. Qué claves se guardan y con qué estructura.\n2. Si hay datos sensibles: contactos, ubicación, salud, emergencias, claves API o textos privados.\n3. Si existe botón claro de borrar datos.\n4. Si hay exportación/importación segura.\n5. Si las claves tienen prefijo propio de la app para evitar colisiones.\n6. Si hay migración de versiones.\n7. Si se controlan errores de cuota, JSON corrupto y modo privado de Safari.\n\n## Salida\nDa:\n- Mapa de datos locales.\n- Riesgos.\n- Cambios concretos.\n- Texto de privacidad para README.\n- Prueba de borrado y recuperación.\n", "bytes": 1070}, {"slug": "loop-engineering-agent", "name": "Loop Engineering Agent", "category": "Agentes", "tags": ["loop", "agente", "auditoría"], "priority": "Media", "description": "Ejecuta un ciclo iterativo de generación, auditoría, corrección y verificación para mejorar código, textos, prompts o productos.", "whenToUse": "El usuario pide loop engineering, versión inicial/auditoría/corrección/segunda auditoría/final, mejorar algo hasta que quede sólido o crear un agente de revisión iterativa.", "useCase": "Cuando quieres un ciclo de versión inicial, auditoría, corrección y versión final.", "command": "/loop-engineering-agent", "example": "/loop-engineering-agent revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Loop Engineering Agent\ndescription: Ejecuta un ciclo iterativo de generación, auditoría, corrección y verificación para mejorar código, textos, prompts o productos.\nwhen_to_use: El usuario pide loop engineering, versión inicial/auditoría/corrección/segunda auditoría/final, mejorar algo hasta que quede sólido o crear un agente de revisión iterativa.\nargument-hint: [objetivo opcional]\n---\n\n# Loop Engineering Agent\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como agente de loop engineering. Tu trabajo no es responder una vez, sino mejorar mediante ciclos cerrados.\n\n## Ciclo obligatorio\n1. Definir objetivo y criterios de éxito.\n2. Crear o revisar la versión actual.\n3. Auditoría dura:\n   - Funcionalidad.\n   - Claridad.\n   - Seguridad.\n   - UX.\n   - Mantenibilidad.\n4. Corregir solo lo que aumente calidad real.\n5. Segunda auditoría.\n6. Versión final o siguiente iteración si quedan bloqueos.\n\n## Reglas\n- No añadir complejidad si no resuelve un problema real.\n- No maquillar bugs con diseño.\n- No decir “perfecto” sin criterios comprobados.\n- Si el input es código, prioriza que funcione.\n- Si el input es texto, prioriza claridad, ritmo e intención.\n\n## Salida\nEntrega:\n- Objetivo detectado.\n- Versión/auditoría/corrección/verificación.\n- Cambios aplicados o propuestos.\n- Próximo paso mínimo.\n", "bytes": 1336}, {"slug": "mobile-touch-auditor", "name": "Mobile Touch Auditor", "category": "UX / Móvil", "tags": ["touch", "iphone", "android", "inputs"], "priority": "Media", "description": "Audita experiencia táctil en móvil: botones, tamaños, scroll, teclado virtual, inputs, safe areas, gestos y errores de interacción.", "whenToUse": "Úsalo cuando una app se ve bien en escritorio pero en móvil cuesta pulsar, se descuadra, el teclado tapa campos o el usuario no entiende qué tocar.", "useCase": "Úsalo cuando una app se ve bien en escritorio pero en móvil cuesta pulsar, se descuadra, el teclado tapa campos o el usuario no entiende qué tocar.", "command": "/mobile-touch-auditor", "example": "/mobile-touch-auditor revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Mobile Touch Auditor\ndescription: Audita experiencia táctil en móvil: botones, tamaños, scroll, teclado virtual, inputs, safe areas, gestos y errores de interacción.\nwhen_to_use: Úsalo cuando una app se ve bien en escritorio pero en móvil cuesta pulsar, se descuadra, el teclado tapa campos o el usuario no entiende qué tocar.\nargument-hint: [pantalla o flujo móvil]\n---\n\n# Mobile Touch Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor móvil táctil para apps web.\n\n## Revisión\n1. Botones y zonas táctiles: mínimo 44px y separación suficiente.\n2. Inputs: labels visibles, `inputmode`, `autocomplete`, tamaño de fuente mínimo 16px en iOS.\n3. Scroll: sin scroll horizontal accidental; contenido crítico visible.\n4. Teclado virtual: no debe tapar acciones esenciales.\n5. Safe areas: revisar notch, barras inferiores y `env(safe-area-inset-*)` si aplica.\n6. Feedback: cada toque debe mostrar estado claro.\n7. Gestos: evitar depender solo de hover o doble click.\n\n## Salida\nEntrega:\n- Problemas de interacción.\n- Cambios CSS/HTML recomendados.\n- Checklist iPhone/Android.\n- Veredicto de usabilidad móvil.\n", "bytes": 1138}, {"slug": "no-dependency-auditor", "name": "No Dependency Auditor", "category": "Dependencias", "tags": ["offline", "cdn", "dependencias", "privacidad"], "priority": "Media", "description": "Comprueba que una app HTML/JS no dependa de CDNs, librerías innecesarias, fuentes externas o recursos que rompan el modo offline.", "whenToUse": "Úsalo cuando la app promete privacidad, offline, uso local o GitHub Pages sin dependencias externas.", "useCase": "Úsalo cuando la app promete privacidad, offline, uso local o GitHub Pages sin dependencias externas.", "command": "/no-dependency-auditor", "example": "/no-dependency-auditor revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: No Dependency Auditor\ndescription: Comprueba que una app HTML/JS no dependa de CDNs, librerías innecesarias, fuentes externas o recursos que rompan el modo offline.\nwhen_to_use: Úsalo cuando la app promete privacidad, offline, uso local o GitHub Pages sin dependencias externas.\nargument-hint: [nivel de privacidad/offline]\n---\n\n# No Dependency Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de dependencias cero.\n\n## Revisión\n1. Busca CDNs: scripts, CSS, fuentes, imágenes, analytics, iframes.\n2. Detecta librerías que pueden sustituirse por JavaScript nativo.\n3. Revisa privacidad: llamadas externas, trackers, APIs de terceros.\n4. Revisa robustez offline: qué falla sin internet.\n5. Revisa licencias si hay assets incluidos.\n6. Propón alternativas locales.\n\n## Salida\nEntrega:\n- Dependencias encontradas.\n- Riesgo de cada una.\n- Qué eliminar, descargar localmente o justificar.\n- Veredicto: offline real / offline parcial / no offline.\n", "bytes": 969}, {"slug": "novelist-editor-hard", "name": "Novelist Editor Hard", "category": "Narrativa", "tags": ["novela", "editor", "literatura"], "priority": "Media", "description": "Audita novelas, capítulos, escenas y prosa con criterio editorial duro: estructura, ritmo, tensión, voz, diálogo, redundancias y publicabilidad.", "whenToUse": "El usuario pide revisar una novela, capítulo, escena, portada literaria, publicación KDP, puntuación editorial, cirugía de prosa o auditoría narrativa dura.", "useCase": "Cuando quieres revisión editorial dura de capítulos, ritmo, prosa y tensión narrativa.", "command": "/novelist-editor-hard", "example": "/novelist-editor-hard revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Novelist Editor Hard\ndescription: Audita novelas, capítulos, escenas y prosa con criterio editorial duro: estructura, ritmo, tensión, voz, diálogo, redundancias y publicabilidad.\nwhen_to_use: El usuario pide revisar una novela, capítulo, escena, portada literaria, publicación KDP, puntuación editorial, cirugía de prosa o auditoría narrativa dura.\nargument-hint: [objetivo opcional]\n---\n\n# Novelist Editor Hard\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como editor literario profesional. Sé útil, no complaciente.\n\n## Revisión por capas\n1. Macroestructura:\n   - Premisa.\n   - Progresión.\n   - Conflicto.\n   - Punto medio.\n   - Clímax.\n   - Cierre.\n2. Capítulo/escena:\n   - Objetivo dramático.\n   - Tensión.\n   - Entrada y salida.\n   - Información nueva.\n   - Repeticiones.\n3. Prosa:\n   - Frases muertas.\n   - Grandilocuencia artificial.\n   - Abstracción excesiva.\n   - Imágenes repetidas.\n4. Diálogo:\n   - Subtexto.\n   - Naturalidad.\n   - Voz diferenciada.\n   - Evitar personajes explicando la trama.\n5. Publicabilidad:\n   - Lo que funciona.\n   - Lo que frena.\n   - Riesgos para lector real.\n\n## Salida\nDa:\n- Nota global /10.\n- Nota por capítulo si aplica.\n- 3 fortalezas reales.\n- 5 problemas prioritarios.\n- Cirugía concreta.\n- Plan de revisión.\n", "bytes": 1279}, {"slug": "ollama-local-planner", "name": "Ollama Local Planner", "category": "IA Local", "tags": ["ollama", "localhost", "modelos", "privacidad"], "priority": "Media", "description": "Planifica integración local con Ollama: modelos, endpoint localhost, fallback sin IA, privacidad, rendimiento y UX.", "whenToUse": "Úsalo cuando una app de escritorio/local quiere IA privada usando Ollama o modelos en localhost.", "useCase": "Úsalo cuando una app de escritorio/local quiere IA privada usando Ollama o modelos en localhost.", "command": "/ollama-local-planner", "example": "/ollama-local-planner revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Ollama Local Planner\ndescription: Planifica integración local con Ollama: modelos, endpoint localhost, fallback sin IA, privacidad, rendimiento y UX.\nwhen_to_use: Úsalo cuando una app de escritorio/local quiere IA privada usando Ollama o modelos en localhost.\nargument-hint: [tipo de app y modelo deseado]\n---\n\n# Ollama Local Planner\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como arquitecto de integración local con Ollama.\n\n## Revisión\n1. Define si la app será web local, Electron o Node.\n2. Usa endpoint local de Ollama solo si el usuario lo tiene instalado.\n3. Añade detección de disponibilidad y mensaje claro si no está activo.\n4. Diseña modo sin IA para que la app siga funcionando.\n5. Evita enviar documentos a servicios externos.\n6. Considera rendimiento: tamaño del modelo, RAM, latencia y streaming.\n7. Define prompts del sistema y límites de contexto.\n\n## Salida\nEntrega:\n- Arquitectura recomendada.\n- Flujo de conexión.\n- Fallback sin Ollama.\n- Riesgos técnicos.\n- Plan de implementación por fases.\n", "bytes": 1032}, {"slug": "prompt-optimizer-claude", "name": "Prompt Optimizer Claude", "category": "Prompts", "tags": ["claude", "prompt", "optimización"], "priority": "Media", "description": "Convierte peticiones desordenadas en prompts profesionales para Claude, con objetivo, contexto, archivos, criterios de éxito, pasos y formato de salida.", "whenToUse": "El usuario pide un prompt para Claude, mejorar una app con Claude, retomar una conversación sin perder contexto, auditar archivos o convertir una idea en instrucciones útiles.", "useCase": "Cuando quieres convertir una idea o prompt flojo en una orden clara para Claude.", "command": "/prompt-optimizer-claude", "example": "/prompt-optimizer-claude revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Prompt Optimizer Claude\ndescription: Convierte peticiones desordenadas en prompts profesionales para Claude, con objetivo, contexto, archivos, criterios de éxito, pasos y formato de salida.\nwhen_to_use: El usuario pide un prompt para Claude, mejorar una app con Claude, retomar una conversación sin perder contexto, auditar archivos o convertir una idea en instrucciones útiles.\nargument-hint: [objetivo opcional]\n---\n\n# Prompt Optimizer Claude\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como arquitecto de prompts para Claude.\n\n## Proceso\n1. Detecta la intención real.\n2. Identifica el resultado esperado.\n3. Añade contexto mínimo necesario.\n4. Convierte la petición en instrucciones verificables.\n5. Incluye criterios de éxito.\n6. Añade restricciones: no romper funciones, no inventar, no borrar sin justificar.\n7. Exige plan antes de tocar código cuando haya riesgo.\n8. Pide pruebas finales.\n\n## Formato de prompt final\nIncluye siempre:\n- Rol de Claude.\n- Objetivo.\n- Archivos a revisar.\n- Problemas conocidos.\n- Tareas obligatorias.\n- Prohibiciones.\n- Criterios de aceptación.\n- Formato de respuesta.\n\n## Tono\nDirecto, profesional y exigente. Evita adornos. El prompt debe ser copiable.\n", "bytes": 1208}, {"slug": "pwa-offline-auditor", "name": "PWA Offline Auditor", "category": "PWA / Offline", "tags": ["pwa", "offline", "service-worker", "manifest"], "priority": "Alta", "description": "Revisa manifest, service worker, caché, instalación, offline-first y compatibilidad móvil de una PWA o app local.", "whenToUse": "El usuario trabaja con manifest.json, sw.js, apps offline, GitHub Pages, móvil, instalación en iPhone/Android o problemas de caché.", "useCase": "Cuando la app tiene manifest, sw.js, modo offline o instalación como PWA.", "command": "/pwa-offline-auditor", "example": "/pwa-offline-auditor revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: PWA Offline Auditor\ndescription: Revisa manifest, service worker, caché, instalación, offline-first y compatibilidad móvil de una PWA o app local.\nwhen_to_use: El usuario trabaja con manifest.json, sw.js, apps offline, GitHub Pages, móvil, instalación en iPhone/Android o problemas de caché.\nargument-hint: [objetivo opcional]\n---\n\n# PWA Offline Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como especialista en PWA offline-first.\n\n## Revisión obligatoria\n1. `manifest.json`:\n   - Nombre corto y largo.\n   - Iconos correctos y tamaños adecuados.\n   - `start_url` compatible con GitHub Pages.\n   - `display`, `theme_color`, `background_color`.\n2. `sw.js`:\n   - Registro correcto.\n   - Cache versionada.\n   - Estrategia clara: cache-first, network-first o stale-while-revalidate.\n   - Activación y limpieza de cachés antiguas.\n   - Sin rutas absolutas rotas.\n3. `index.html`:\n   - Meta viewport.\n   - Theme color.\n   - Enlace al manifest.\n   - Registro del service worker con manejo de errores.\n4. Funcionamiento offline:\n   - Carga inicial online.\n   - Recarga offline.\n   - Recursos internos disponibles.\n5. iOS/Safari:\n   - Apple touch icon.\n   - Safe areas si aplica.\n   - Evitar APIs no soportadas sin fallback.\n\n## Criterio\nUna PWA no está lista si funciona solo por caché accidental, si el service worker impide ver cambios, o si falla al estar en una subcarpeta de GitHub Pages.\n\n## Salida\nDa un diagnóstico con:\n- Estado PWA: verde/ámbar/rojo.\n- Archivos a tocar.\n- Riesgos de caché.\n- Prueba offline paso a paso.\n\n\n## Evidencia mínima antes del veredicto\nAntes de decir que algo está listo, intenta obtener evidencia del proyecto real: estructura de archivos, puntos de entrada, errores visibles, flujo principal y pruebas reproducibles. Si no puedes ejecutar o abrir la app, dilo como limitación y da una checklist manual.\n", "bytes": 1862}, {"slug": "readme-github-pro", "name": "README GitHub Pro", "category": "Documentación", "tags": ["readme", "docs", "github"], "priority": "Media", "description": "Genera o mejora un README profesional para proyectos GitHub, con instalación, uso, capturas, privacidad, estructura, roadmap y GitHub Pages.", "whenToUse": "El usuario pide preparar para GitHub, crear documentación, mejorar README, explicar cómo ejecutar una app o hacer que el proyecto parezca serio.", "useCase": "Cuando necesitas un README serio con instalación, uso, estructura, capturas y roadmap.", "command": "/readme-github-pro", "example": "/readme-github-pro revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: README GitHub Pro\ndescription: Genera o mejora un README profesional para proyectos GitHub, con instalación, uso, capturas, privacidad, estructura, roadmap y GitHub Pages.\nwhen_to_use: El usuario pide preparar para GitHub, crear documentación, mejorar README, explicar cómo ejecutar una app o hacer que el proyecto parezca serio.\nargument-hint: [objetivo opcional]\n---\n\n# README GitHub Pro\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como técnico de documentación de producto.\n\n## Objetivo\nCrear un README claro, serio y útil para que cualquier persona entienda qué hace la app, cómo ejecutarla y qué limitaciones tiene.\n\n## Estructura recomendada\n1. Título del proyecto.\n2. Descripción breve y directa.\n3. Captura o sección para captura.\n4. Funciones principales.\n5. Demo en GitHub Pages si aplica.\n6. Uso local paso a paso.\n7. Estructura de archivos.\n8. Privacidad y datos.\n9. Compatibilidad.\n10. Roadmap.\n11. Licencia.\n12. Autor.\n\n## Tono\nProfesional, claro y sin humo. No vender como SaaS si es una app estática. No prometer IA real si no hay modelo/API detrás.\n\n## Salida\nDevuelve el README completo en Markdown listo para copiar o guardar como `README.md`.\n", "bytes": 1182}, {"slug": "release-finalizer", "name": "Release Finalizer", "category": "Release", "tags": ["release", "limpieza", "github"], "priority": "Alta", "description": "Prepara una versión final seria para GitHub: limpieza, estructura, README, changelog, licencia, seguridad, pruebas y checklist de release.", "whenToUse": "El usuario pide versión final, zip listo para GitHub, empaquetado, eliminar textos provisionales, dejarlo perfecto, preparar release o subir a GitHub Pages.", "useCase": "Cuando quieres dejar el proyecto como versión final limpia, sin archivos basura ni mensajes feos.", "command": "/release-finalizer", "example": "/release-finalizer revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Release Finalizer\ndescription: Prepara una versión final seria para GitHub: limpieza, estructura, README, changelog, licencia, seguridad, pruebas y checklist de release.\nwhen_to_use: El usuario pide versión final, zip listo para GitHub, empaquetado, eliminar textos provisionales, dejarlo perfecto, preparar release o subir a GitHub Pages.\nargument-hint: [objetivo opcional]\n---\n\n# Release Finalizer\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como responsable de release. Tu misión es dejar el proyecto limpio, coherente y publicable.\n\n## Revisión de release\n1. Estructura:\n   - `index.html`, `style.css`, `app.js` o estructura equivalente.\n   - Eliminar duplicados, backups, capturas temporales y archivos basura.\n2. Identidad:\n   - Nombre de app consistente en HTML, manifest, README y título.\n   - Quitar textos provisionales tipo “debug”, “versión sin caché”, “recomendado” si no aportan.\n3. Documentación:\n   - README con descripción, funciones, uso, instalación, GitHub Pages, privacidad y roadmap.\n   - LICENSE clara.\n   - CHANGELOG con versión.\n   - SECURITY si maneja datos.\n4. Pruebas:\n   - Abrir localmente.\n   - Probar en móvil/responsive.\n   - Revisar consola.\n   - Probar flujo principal 3 veces seguidas.\n5. GitHub Pages:\n   - Rutas relativas.\n   - Sin dependencias locales rotas.\n   - Sin claves privadas.\n\n## Criterio\nNo uses “definitiva absoluta” salvo que exista evidencia de prueba. Usa “release candidate” si quedan validaciones manuales.\n\n## Salida\nEntrega:\n- Estado de release.\n- Lista exacta de archivos finales.\n- Cosas eliminadas.\n- Comandos o pasos para subir a GitHub.\n- Checklist final.\n\n\n## Evidencia mínima antes del veredicto\nAntes de decir que algo está listo, intenta obtener evidencia del proyecto real: estructura de archivos, puntos de entrada, errores visibles, flujo principal y pruebas reproducibles. Si no puedes ejecutar o abrir la app, dilo como limitación y da una checklist manual.\n", "bytes": 1968}, {"slug": "safari-ios-compat-auditor", "name": "Safari iOS Compat Auditor", "category": "Safari / iOS", "tags": ["iphone", "safari", "compatibilidad"], "priority": "Alta", "description": "Revisa compatibilidad con Safari/iPhone: APIs no soportadas, PWA, viewport, botones, audio, compartir, copiar al portapapeles, localStorage y responsive.", "whenToUse": "El usuario dice que en Safari no va, algo no se ve bien en iPhone, el audio no suena, no se copia, no detecta QR o la PWA falla en iOS.", "useCase": "Cuando algo funciona en Chrome pero falla en iPhone/Safari.", "command": "/safari-ios-compat-auditor", "example": "/safari-ios-compat-auditor revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Safari iOS Compat Auditor\ndescription: Revisa compatibilidad con Safari/iPhone: APIs no soportadas, PWA, viewport, botones, audio, compartir, copiar al portapapeles, localStorage y responsive.\nwhen_to_use: El usuario dice que en Safari no va, algo no se ve bien en iPhone, el audio no suena, no se copia, no detecta QR o la PWA falla en iOS.\nargument-hint: [síntoma en iPhone/Safari]\n---\n\n# Safari iOS Compat Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor específico de Safari/iOS.\n\n## Revisión obligatoria\n1. APIs con soporte irregular: Clipboard, Share, Audio autoplay, Wake Lock, File System Access, Web Speech, Notifications.\n2. Eventos táctiles y teclado móvil.\n3. Viewport, safe areas, zoom involuntario en inputs, tamaño de botones.\n4. PWA iOS: iconos, `apple-touch-icon`, `theme-color`, instalación y service worker.\n5. Audio: debe iniciarse tras interacción del usuario.\n6. QR/canvas: contraste, tamaño, margen y descarga/copia.\n7. Fallbacks visibles cuando una API no existe.\n\n## Salida\nEntrega:\n- Causa más probable.\n- APIs sospechosas.\n- Cambios por archivo.\n- Fallback recomendado.\n- Prueba manual en iPhone.\n", "bytes": 1154}, {"slug": "security-privacy-review", "name": "Security Privacy Review", "category": "Seguridad", "tags": ["privacidad", "seguridad", "local", "datos"], "priority": "Alta", "description": "Revisa privacidad y seguridad en apps locales, formularios, localStorage, claves API, datos sensibles, XSS, dependencias y exposición accidental.", "whenToUse": "El usuario pregunta por seguridad, datos sensibles, API keys, apps con login, formularios, localStorage, privacidad, GitHub público o uso por gente mayor.", "useCase": "Cuando manejas claves API, datos sensibles, formularios, localStorage o privacidad.", "command": "/security-privacy-review", "example": "/security-privacy-review revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Security Privacy Review\ndescription: Revisa privacidad y seguridad en apps locales, formularios, localStorage, claves API, datos sensibles, XSS, dependencias y exposición accidental.\nwhen_to_use: El usuario pregunta por seguridad, datos sensibles, API keys, apps con login, formularios, localStorage, privacidad, GitHub público o uso por gente mayor.\nargument-hint: [objetivo opcional]\n---\n\n# Security Privacy Review\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como revisor de seguridad pragmático para apps locales, PWAs y proyectos frontend.\n\n## Revisión mínima\n1. Datos sensibles:\n   - ¿Se guardan en localStorage/sessionStorage?\n   - ¿Se exponen en HTML, JS o logs?\n   - ¿Hay datos médicos, contactos, ubicación o emergencias?\n2. API keys:\n   - No deben estar hardcodeadas en frontend público.\n   - Si cada usuario pone su clave, debe poder verla, cambiarla, borrarla y saber dónde se guarda.\n3. XSS e inyección:\n   - Evitar `innerHTML` con entrada de usuario.\n   - Sanitizar contenido o usar `textContent`.\n4. Red:\n   - Confirmar si la app envía datos fuera.\n   - Informar claramente al usuario.\n5. Dependencias:\n   - Evitar CDNs innecesarios si la app promete offline.\n6. GitHub público:\n   - No incluir claves, datos reales, zips innecesarios ni backups.\n7. Emergencias/personas mayores:\n   - No prometer sustitución de servicios de emergencia.\n   - Añadir confirmaciones, contactos fiables y mensajes claros.\n\n## Salida\nClasifica cada riesgo:\n- Crítico: exposición real de claves/datos o función peligrosa.\n- Alto: datos sensibles sin aviso o sin borrado.\n- Medio: malas prácticas mitigables.\n- Bajo: mejoras de transparencia.\n\nIncluye cambios concretos de código o texto legal si procede.\n", "bytes": 1725}, {"slug": "systematic-debugger", "name": "Systematic Debugger", "category": "Debugging", "tags": ["bugs", "causa raíz", "testing"], "priority": "Alta", "description": "Depura errores de forma sistemática: reproducir, aislar causa raíz, corregir, probar y evitar arreglos a ciegas.", "whenToUse": "El usuario dice que algo no funciona, se queda parado, crashea, no responde, falla en Safari, no detecta QR, no arranca, o pide revisar un bug concreto.", "useCase": "Cuando algo no funciona, se queda parado, falla al segundo intento o necesitas encontrar la causa raíz.", "command": "/systematic-debugger", "example": "/systematic-debugger revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Systematic Debugger\ndescription: Depura errores de forma sistemática: reproducir, aislar causa raíz, corregir, probar y evitar arreglos a ciegas.\nwhen_to_use: El usuario dice que algo no funciona, se queda parado, crashea, no responde, falla en Safari, no detecta QR, no arranca, o pide revisar un bug concreto.\nargument-hint: [objetivo opcional]\n---\n\n# Systematic Debugger\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como depurador sistemático. No improvises parches hasta entender el fallo.\n\n## Proceso obligatorio\n1. Define el síntoma exacto.\n2. Localiza el flujo que falla.\n3. Busca el archivo y la función responsables.\n4. Formula una hipótesis de causa raíz.\n5. Verifica si la hipótesis encaja con el código.\n6. Aplica el cambio mínimo que corrige la causa, no el síntoma.\n7. Revisa efectos secundarios.\n8. Propón una prueba manual reproducible.\n\n## Antipatrones prohibidos\n- Cambiar muchos archivos sin justificarlo.\n- Añadir una librería para tapar un bug simple.\n- Reiniciar estados sin explicar por qué.\n- Culpar al navegador sin revisar eventos, listeners, promesas y errores.\n- Decir “limpia caché” como única solución.\n\n## Cuando sea una app de chat local\nComprueba especialmente:\n- Estado `isTyping`, `isBusy` o similar.\n- Listeners duplicados.\n- Promesas sin `finally`.\n- Bloqueos tras la primera respuesta.\n- Historial mal actualizado.\n- Errores silenciosos en `try/catch`.\n\n## Salida\nEntrega:\n- Causa probable.\n- Archivo afectado.\n- Cambio exacto.\n- Prueba para confirmar.\n- Riesgo de regresión.\n\n\n## Evidencia mínima antes del veredicto\nAntes de decir que algo está listo, intenta obtener evidencia del proyecto real: estructura de archivos, puntos de entrada, errores visibles, flujo principal y pruebas reproducibles. Si no puedes ejecutar o abrir la app, dilo como limitación y da una checklist manual.\n", "bytes": 1855}, {"slug": "test-plan-generator", "name": "Test Plan Generator", "category": "Testing", "tags": ["pruebas", "qa", "checklist"], "priority": "Alta", "description": "Genera un plan de pruebas manuales y técnicas para apps web/locales antes de declararlas versión final.", "whenToUse": "El usuario pregunta si una app está perfecta, lista para GitHub, sin bugs, o necesita pruebas de flujo, móvil, consola, seguridad y PWA.", "useCase": "Cuando necesitas pruebas manuales reales antes de decir “versión final”.", "command": "/test-plan-generator", "example": "/test-plan-generator revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: Test Plan Generator\ndescription: Genera un plan de pruebas manuales y técnicas para apps web/locales antes de declararlas versión final.\nwhen_to_use: El usuario pregunta si una app está perfecta, lista para GitHub, sin bugs, o necesita pruebas de flujo, móvil, consola, seguridad y PWA.\nargument-hint: [tipo de app]\n---\n\n# Test Plan Generator\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como QA tester pragmático.\n\n## Plan mínimo\n1. Smoke test: abrir app, cargar assets, consola limpia.\n2. Flujo principal repetido 3 veces.\n3. Inputs vacíos, extremos y caracteres raros.\n4. Persistencia: guardar, recargar, borrar.\n5. Responsive: móvil estrecho, tablet y escritorio.\n6. Safari/iPhone si aplica.\n7. Offline/PWA si aplica.\n8. Accesibilidad básica: teclado, foco, contraste, labels.\n9. Seguridad: XSS simple, claves, datos locales.\n10. Release: README, LICENSE, rutas relativas.\n\n## Salida\nEntrega una tabla con:\n- ID de prueba.\n- Qué probar.\n- Pasos.\n- Resultado esperado.\n- Estado: pendiente/pasa/falla.\n- Prioridad.\n", "bytes": 1030}, {"slug": "ui-ux-mobile-auditor", "name": "UI UX Mobile Auditor", "category": "UX / Móvil", "tags": ["responsive", "móvil", "interfaz"], "priority": "Media", "description": "Audita interfaz, experiencia móvil, responsive, accesibilidad básica, legibilidad, jerarquía visual y microcopy.", "whenToUse": "El usuario enseña capturas, dice que algo se ve raro, descuadrado, no queda bien, tapa elementos, no se ve en Safari/iPhone o pide diseño más profesional.", "useCase": "Cuando una app se ve mal en móvil, botones descuadrados, textos pequeños o navegación confusa.", "command": "/ui-ux-mobile-auditor", "example": "/ui-ux-mobile-auditor revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: UI UX Mobile Auditor\ndescription: Audita interfaz, experiencia móvil, responsive, accesibilidad básica, legibilidad, jerarquía visual y microcopy.\nwhen_to_use: El usuario enseña capturas, dice que algo se ve raro, descuadrado, no queda bien, tapa elementos, no se ve en Safari/iPhone o pide diseño más profesional.\nargument-hint: [objetivo opcional]\n---\n\n# UI UX Mobile Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como diseñador UX/UI senior con criterio móvil-first.\n\n## Revisión\n1. Jerarquía visual:\n   - Título claro.\n   - Acción principal evidente.\n   - Secundarios sin competir.\n2. Responsive:\n   - Sin desbordes horizontales.\n   - Botones táctiles de al menos 44px.\n   - Espaciado cómodo.\n   - Formularios legibles en móvil.\n3. Accesibilidad:\n   - Contraste suficiente.\n   - Labels visibles o accesibles.\n   - Foco de teclado.\n   - Texto no minúsculo en exceso.\n4. Estado de la app:\n   - Loading, vacío, error, éxito.\n   - Feedback inmediato tras pulsar.\n5. Microcopy:\n   - Quitar frases técnicas internas.\n   - Evitar claims falsos.\n   - Explicar acciones críticas.\n6. Estética:\n   - Coherencia de color, sombras, iconos, borde y tono.\n\n## Salida\nDa:\n- Diagnóstico visual.\n- 5 mejoras de mayor impacto.\n- CSS/HTML recomendado si procede.\n- Checklist de prueba en móvil.\n", "bytes": 1313}, {"slug": "zip-release-builder", "name": "ZIP Release Builder", "category": "Release", "tags": ["zip", "release", "empaquetado", "github"], "priority": "Alta", "description": "Prepara un ZIP final limpio para publicar: estructura, nombres, exclusiones, README, versión, changelog y validación básica.", "whenToUse": "Úsalo cuando el usuario quiere “devuélvemelo listo para GitHub”, “empaquetado final” o “versión definitiva”.", "useCase": "Úsalo cuando el usuario quiere “devuélvemelo listo para GitHub”, “empaquetado final” o “versión definitiva”.", "command": "/zip-release-builder", "example": "/zip-release-builder revisa este proyecto y dame un veredicto claro con pasos concretos.", "content": "---\nname: ZIP Release Builder\ndescription: Prepara un ZIP final limpio para publicar: estructura, nombres, exclusiones, README, versión, changelog y validación básica.\nwhen_to_use: Úsalo cuando el usuario quiere “devuélvemelo listo para GitHub”, “empaquetado final” o “versión definitiva”.\nargument-hint: [nombre del release]\n---\n\n# ZIP Release Builder\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como responsable de empaquetado de release.\n\n## Proceso\n1. Define carpeta raíz limpia con nombre y versión.\n2. Incluye solo archivos necesarios.\n3. Excluye: `.git`, `node_modules`, logs, backups, capturas privadas, zips antiguos, archivos temporales.\n4. Verifica `README`, `LICENSE`, `CHANGELOG`, `.gitignore` y estructura.\n5. Sincroniza versión en archivos relevantes.\n6. Añade checklist de publicación.\n7. Genera nombre de ZIP claro.\n\n## Salida\nEntrega:\n- Árbol de archivos final.\n- Archivos excluidos.\n- Nombre del ZIP.\n- Comandos Git sugeridos.\n- Prueba mínima antes de publicar.\n", "bytes": 1000}];
const CATEGORIES = ["Accesibilidad", "Agentes", "Apps / GitHub", "Arquitectura Local", "Compatibilidad", "Contexto", "Datos Locales", "Debugging", "Dependencias", "Documentación", "GitHub Pages", "IA / Producto", "IA / Seguridad", "IA Local", "KDP / Publicación", "Marca / Creativo", "Narrativa", "PWA / Offline", "Producto", "Prompts", "Release", "Safari / iOS", "Seguridad", "Skills", "Testing", "UX / Móvil"];
const PACK_FILES = {".gitattributes": "* text=auto eol=lf\n*.ps1 text eol=crlf\n*.sh text eol=lf\n*.md text eol=lf\n*.json text eol=lf\n", ".github/ISSUE_TEMPLATE/bug_report.yml": "name: Bug report\ndescription: Report a problem with the pack or a Skill\ntitle: \"[Bug]: \"\nlabels: [bug]\nbody:\n  - type: textarea\n    id: problem\n    attributes:\n      label: Problem\n      description: What failed?\n    validations:\n      required: true\n  - type: textarea\n    id: expected\n    attributes:\n      label: Expected behavior\n    validations:\n      required: true\n  - type: textarea\n    id: context\n    attributes:\n      label: Context\n      description: Claude Code version, OS, Skill name and command used.\n", ".github/ISSUE_TEMPLATE/skill_request.yml": "name: Skill request\ndescription: Suggest a new Skill or improvement\ntitle: \"[Skill]: \"\nlabels: [enhancement]\nbody:\n  - type: input\n    id: skill-name\n    attributes:\n      label: Proposed Skill name\n    validations:\n      required: true\n  - type: textarea\n    id: workflow\n    attributes:\n      label: Workflow it should solve\n      description: Describe the repeated task this Skill should handle.\n    validations:\n      required: true\n  - type: textarea\n    id: output\n    attributes:\n      label: Expected output\n", ".github/PULL_REQUEST_TEMPLATE.md": "# Pull request\n\n## Summary\n\nDescribe the change.\n\n## Checklist\n\n- [ ] I ran `python scripts/validate-skills-pack.py`.\n- [ ] I updated docs if needed.\n- [ ] I did not include secrets, logs, private files or generated ZIPs.\n- [ ] The change improves a real workflow.\n", ".github/workflows/validate.yml": "name: Validate Skills Pack\n\non:\n  push:\n  pull_request:\n\njobs:\n  validate:\n    runs-on: ubuntu-latest\n    steps:\n      - name: Checkout\n        uses: actions/checkout@v4\n      - name: Set up Python\n        uses: actions/setup-python@v5\n        with:\n          python-version: '3.x'\n      - name: Validate Skills\n        run: python scripts/validate-skills-pack.py\n      - name: Check JavaScript syntax\n        run: |\n          node --check app.js\n          node --check sw.js\n", ".gitignore": "# OS\n.DS_Store\nThumbs.db\n\n# Editors\n.vscode/\n.idea/\n\n# Logs\n*.log\n\n# Node/Python caches\nnode_modules/\n__pycache__/\n*.pyc\n\n# Build artifacts\n/dist/\n/build/\n\n# Local env\n.env\n.env.*\n", "CHANGELOG.md": "# Changelog\n\n## 1.3.2\n- Ampliado el pack de 19 a 33 Skills.\n- Añadidas Skills de consola, rutas GitHub Pages, mobile touch, local-first, pulido de producto, compatibilidad, dependencias cero y empaquetado ZIP.\n- Añadidas Skills de API keys, diseño de funciones IA, Ollama local, landing oscura, biblia narrativa y checklist KDP.\n- Actualizada la web para mostrar 33 Skills y descargar el pack v1.3.2.\n- Actualizado service worker para evitar caché antigua.\n\n## 1.2.1\n- Preparado para GitHub como repositorio publicable.\n- Añadidos `.gitignore`, `.gitattributes`, `SECURITY.md`, `CONTRIBUTING.md`, `CODE_OF_CONDUCT.md` y `RELEASE-CHECKLIST.md`.\n- Añadidas plantillas de issues, pull request y workflow de validación.\n- Añadida documentación en `docs/` y ejemplos en `examples/`.\n- Actualizado `skills-manifest.json` a 1.2.1.\n\n## 1.1.0\n- Añadidas Skills: Codebase Context Loader, GitHub Pages Deploy Check, Safari iOS Compat Auditor, Local Storage Data Auditor, Test Plan Generator, Claude Skill Builder y Accessibility Basic Auditor.\n- Añadido bloque `$ARGUMENTS` a todas las Skills para que la invocación directa conserve el objetivo del usuario.\n- Añadidos instaladores por proyecto.\n- Añadido validador del pack.\n- README ampliado con uso personal/proyecto y prueba de instalación.\n\n## 1.0.0\n- Pack inicial con 12 Skills para apps, PWA, debugging, seguridad, release, prompts, narrativa y voz de marca.\n", "CODE_OF_CONDUCT.md": "# Code of Conduct\n\nBe respectful, practical and constructive. This repository is focused on improving workflows, documentation and reusable Claude Code Skills.\n\nUnacceptable behavior includes harassment, personal attacks, spam, malicious code, credential harvesting, or attempts to include private/sensitive data in examples.\n", "CONTRIBUTING.md": "# Contributing\n\nContributions are welcome if they improve clarity, reliability or practical usefulness.\n\n## Rules\n\n1. Keep each Skill focused on a real workflow.\n2. Keep `SKILL.md` concise. Move long references to supporting files.\n3. Use clear Spanish by default.\n4. Do not add secrets, private files, telemetry or vendor lock-in.\n5. Run the validator before opening a pull request:\n\n```bash\npython scripts/validate-skills-pack.py\n```\n\n## Pull request checklist\n\n- [ ] The Skill has a valid `SKILL.md`.\n- [ ] Frontmatter includes a useful `description`.\n- [ ] Instructions are actionable, not vague.\n- [ ] README/docs are updated if needed.\n- [ ] No private data or generated archives are committed.\n", "LICENSE": "MIT License\n\nCopyright (c) 2026 I. Roig\n\nPermission is hereby granted, free of charge, to any person obtaining a copy\nof this software and associated documentation files (the \"Software\"), to deal\nin the Software without restriction, including without limitation the rights\nto use, copy, modify, merge, publish, distribute, sublicense, and/or sell\ncopies of the Software, and to permit persons to whom the Software is\nfurnished to do so, subject to the following conditions:\n\nThe above copyright notice and this permission notice shall be included in all\ncopies or substantial portions of the Software.\n\nTHE SOFTWARE IS PROVIDED \"AS IS\", WITHOUT WARRANTY OF ANY KIND, EXPRESS OR\nIMPLIED, INCLUDING BUT NOT LIMITED TO THE WARRANTIES OF MERCHANTABILITY,\nFITNESS FOR A PARTICULAR PURPOSE AND NONINFRINGEMENT. IN NO EVENT SHALL THE\nAUTHORS OR COPYRIGHT HOLDERS BE LIABLE FOR ANY CLAIM, DAMAGES OR OTHER\nLIABILITY, WHETHER IN AN ACTION OF CONTRACT, TORT OR OTHERWISE, ARISING FROM,\nOUT OF OR IN CONNECTION WITH THE SOFTWARE OR THE USE OR OTHER DEALINGS IN THE\nSOFTWARE.\n", "PROMPTS-SIN-CLAUDE-CODE.md": "# Prompts de emergencia si no usas Claude Code\n\nSi no puedes instalar Skills, copia uno de estos comandos al inicio de una conversación de Claude y pega después tus archivos o código.\n\n## Auditor total de app GitHub\n\nActúa como arquitecto senior frontend, auditor de producto y QA. Revisa esta app HTML/CSS/JS como si tuviera que publicarse en GitHub Pages. No me digas que está perfecta salvo que compruebes estructura, flujo principal, errores de consola, responsive, accesibilidad básica, seguridad, rutas, README y compatibilidad móvil. Entrega: veredicto directo, fallos críticos, mejoras por archivo, plan de corrección y checklist final. Si no puedes ejecutar la app, dilo claramente y dame pruebas manuales.\n\n## Depurador sistemático\n\nActúa como depurador sistemático. No propongas parches a ciegas. Primero define el síntoma, luego localiza el flujo que falla, identifica la causa raíz, aplica el cambio mínimo, revisa efectos secundarios y dame una prueba manual reproducible para confirmar que ya funciona.\n\n## Release final\n\nActúa como responsable de release. Limpia el proyecto, elimina textos provisionales, revisa nombres, README, LICENSE, SECURITY, CHANGELOG, rutas relativas y compatibilidad GitHub Pages. Devuelve la lista exacta de archivos finales y un checklist de publicación. Usa “release candidate” si quedan pruebas manuales pendientes.\n\n## Auditor Safari/iPhone\n\nActúa como auditor específico de Safari/iOS. Revisa APIs no soportadas, audio, clipboard, share, service worker, viewport, safe areas, botones táctiles, localStorage en modo privado, QR/canvas y fallbacks. Dame causa probable, cambios concretos y prueba manual en iPhone.\n\n## Editor literario duro\n\nActúa como editor literario profesional. Revisa este texto sin complacencia: estructura, tensión, ritmo, voz, diálogo, redundancias, escenas que sobran y publicabilidad. Da nota /10, fortalezas reales, problemas prioritarios y plan de revisión.\n\n## Cazador de errores de consola\n\nActúa como cazador de errores de consola en JavaScript. No hagas cambios a ciegas. Revisa errores rojos, promesas sin catch/finally, listeners duplicados, selectores null, estado busy/loading bloqueado e innerHTML que borra nodos. Entrega causa raíz, archivo afectado, cambio exacto y prueba de regresión.\n\n## Auditor GitHub Pages rutas\n\nActúa como especialista en GitHub Pages. Revisa rutas relativas, assets, CSS/JS, manifest, iconos, service worker y descargas cuando la app se publica en subcarpeta. Entrega cambios por archivo y prueba local/publicada.\n\n## Planificador API Key segura\n\nActúa como arquitecto de seguridad para una app que usa una API key introducida por el usuario. Diseña almacenamiento, borrado, avisos, costes, límites y flujo seguro. Nunca propongas claves hardcodeadas en frontend público.\n\n## Arquitecto local-first\n\nActúa como arquitecto local-first. Diseña una app que funcione sin servidor, con privacidad, exportación/importación de datos, borrado y modo offline real. Entrega arquitectura, riesgos y MVP.\n\n## Checklist KDP\n\nActúa como responsable de lanzamiento editorial en KDP. Revisa manuscrito, portada, descripción, categorías, keywords, precio, vista previa Kindle y plan de publicación. Da riesgos y prioridades.\n\n", "README.md": "# I. Roig Claude Skills Pack · Web App\n\nPanel web estático para explorar, copiar, descargar y documentar el **I. Roig Claude Skills Pack**.\n\nFunciona con **HTML + CSS + JavaScript puro**, sin dependencias externas y preparado para **GitHub Pages**.\n\n## Qué incluye\n\n- Catálogo visual de 33 Claude Skills.\n- Buscador y filtros por categoría.\n- Favoritas con `localStorage`.\n- Generador de flujos de comandos para Claude Code.\n- Descarga de `SKILL.md` individual.\n- Generación de ZIP del pack directamente en el navegador.\n- Botón de descarga del ZIP del pack v1.3.2.\n- Checklist de release guardado en local.\n- Notas locales privadas.\n- Modo claro/oscuro.\n- PWA offline cuando se sirve por HTTPS.\n\n## Nuevas Skills v1.3.2\n\n- `console-error-hunter`\n- `github-pages-path-fixer`\n- `mobile-touch-auditor`\n- `local-first-architecture`\n- `app-product-polisher`\n- `browser-compatibility-auditor`\n- `no-dependency-auditor`\n- `zip-release-builder`\n- `api-key-safety-planner`\n- `ai-feature-designer`\n- `ollama-local-planner`\n- `dark-landing-page-writer`\n- `fiction-world-bible-builder`\n- `kdp-launch-checklist`\n\n## Uso local\n\nAbre `index.html` directamente en el navegador.\n\nPara probar como servidor local:\n\n```bash\npython -m http.server 8080\n```\n\nLuego abre:\n\n```text\nhttp://localhost:8080\n```\n\n## Publicar en GitHub Pages\n\n1. Crea un repositorio nuevo.\n2. Sube todos los archivos.\n3. Ve a **Settings → Pages**.\n4. En **Build and deployment**, selecciona:\n   - Source: `Deploy from a branch`\n   - Branch: `main`\n   - Folder: `/root`\n5. Guarda.\n\n## Instalar las Skills en Claude Code\n\nWindows:\n\n```powershell\n./install-windows.ps1\n```\n\nmacOS / Linux:\n\n```bash\nchmod +x install-macos-linux.sh\n./install-macos-linux.sh\n```\n\n## Estructura\n\n```text\nindex.html\nstyle.css\napp.js\nmanifest.json\nsw.js\nicons/\ndownloads/\nskills/\ndocs/\nexamples/\nscripts/\n```\n\n## Estado v1.3.2\n\n- Ampliado de 19 a 33 Skills.\n- Añadidas Skills para consola, rutas de GitHub Pages, móvil táctil, arquitectura local-first, pulido de producto, compatibilidad, dependencias cero, ZIP releases, API keys, diseño IA, Ollama, landing oscura, biblia narrativa y KDP.\n- Sincronizados `VERSION`, `skills-manifest.json`, web app y ZIP descargable.\n- Listo para GitHub Pages tras prueba manual en navegador.\n\n## Nota\n\nLa web no instala automáticamente archivos en `~/.claude/skills/`, porque el navegador no puede escribir en carpetas internas del sistema por seguridad. Sí permite descargar, copiar comandos y guiar la instalación.\n", "RELEASE-CHECKLIST.md": "# Release Checklist\n\n- [ ] Abrir `index.html` en local.\n- [ ] Probar buscador y filtros.\n- [ ] Abrir una Skill.\n- [ ] Copiar comando.\n- [ ] Descargar `SKILL.md` individual.\n- [ ] Generar ZIP desde el navegador.\n- [ ] Revisar responsive móvil.\n- [ ] Probar modo claro/oscuro.\n- [ ] Probar notas y checklist localStorage.\n- [ ] Publicar en GitHub Pages.\n- [ ] Validar que `sw.js` no rompe rutas en subcarpeta.\n", "SECURITY.md": "# Security Policy\n\n## Supported versions\n\nThe current maintained version is the latest release in this repository.\n\n## Reporting a vulnerability\n\nDo not open a public issue for sensitive security problems. Contact the maintainer privately if possible, or open a minimal issue without secrets, tokens, private files, screenshots with credentials, or personal data.\n\n## Scope\n\nThis repository contains Claude Code Skills, scripts and documentation. It should not contain API keys, tokens, user data, private project files or credentials.\n\n## User responsibility\n\nBefore publishing forks or examples, check that no private files, Claude sessions, API keys, logs or real personal data are included.\n", "VERSION": "1.3.2\n", "checklists/CHECKLIST-APP-GITHUB.md": "# Checklist rápido para declarar una app lista para GitHub\n\n- [ ] Abre en local sin errores de consola.\n- [ ] El flujo principal funciona 3 veces seguidas.\n- [ ] Responsive probado en móvil estrecho.\n- [ ] Safari/iPhone revisado si aplica.\n- [ ] No hay claves ni datos reales.\n- [ ] `README.md` explica uso, privacidad y publicación.\n- [ ] `LICENSE`, `.gitignore`, `CHANGELOG.md` si corresponde.\n- [ ] Rutas relativas compatibles con GitHub Pages.\n- [ ] Service worker versionado si es PWA.\n- [ ] Botón de borrar datos si usa almacenamiento local.\n", "docs/GITHUB-PUBLISHING.md": "# Publishing to GitHub\n\n## First publish\n\n```bash\ngit init\ngit add .\ngit commit -m \"Initial release: I. Roig Claude Skills Pack v1.3.2\"\ngit branch -M main\ngit remote add origin https://github.com/TU-USUARIO/i-roig-claude-skills-pack.git\ngit push -u origin main\n```\n\n## Create a release\n\n```bash\ngit tag v1.3.2\ngit push origin v1.3.2\n```\n\nThen create a GitHub Release from the tag and attach the ZIP if desired.\n\n## Recommended repository settings\n\n- Description: `Claude Code Skills pack for app auditing, debugging, PWA, security, releases, prompts, local-first apps and fiction editing.`\n- Topics: `claude-code`, `skills`, `ai-tools`, `prompts`, `github-pages`, `pwa`, `debugging`, `frontend`, `writing`, `ollama`\n- License: MIT\n", "docs/INSTALLATION.md": "# Installation\n\n## Personal installation\n\nPersonal Skills are available in all Claude Code projects.\n\n### Windows\n\n```powershell\n.\\install-windows.ps1\n```\n\n### macOS / Linux\n\n```bash\nchmod +x install-macos-linux.sh\n./install-macos-linux.sh\n```\n\n## Project-only installation\n\nUse this when you want the Skills copied into one repository only.\n\n### Windows\n\n```powershell\n.\\install-project.ps1\n```\n\n### macOS / Linux\n\n```bash\nchmod +x install-project.sh\n./install-project.sh\n```\n\nThe destination is:\n\n```text\n.claude/skills/\n```\n\n## Verify installation\n\nOpen Claude Code in a project and run:\n\n```text\n/github-app-auditor revisa este repositorio\n```\n", "docs/USAGE.md": "# Usage\n\n## App audit flow\n\n```text\n/codebase-context-loader Primero entiende este repo.\n/github-app-auditor Revisa si está listo para GitHub.\n/console-error-hunter Busca errores de consola y promesas rotas.\n/security-privacy-review Revisa claves, localStorage y datos sensibles.\n/test-plan-generator Crea pruebas finales.\n/release-finalizer Déjalo como release candidate.\n```\n\n## PWA / GitHub Pages flow\n\n```text\n/pwa-offline-auditor Revisa manifest, service worker y modo offline.\n/github-pages-path-fixer Corrige rutas, assets y compatibilidad con subcarpeta.\n/safari-ios-compat-auditor Revisa iPhone/Safari.\n/browser-compatibility-auditor Revisa Chrome, Edge, Firefox y Safari.\n```\n\n## App local-first flow\n\n```text\n/local-first-architecture Diseña la arquitectura local/offline.\n/no-dependency-auditor Comprueba que no depende de CDNs ni recursos externos.\n/local-storage-data-auditor Revisa persistencia, exportación y borrado.\n```\n\n## AI app flow\n\n```text\n/ai-feature-designer Decide si conviene IA real, motor local u Ollama.\n/api-key-safety-planner Diseña manejo seguro de claves API.\n/ollama-local-planner Planifica integración local con Ollama si aplica.\n```\n\n## Writing flow\n\n```text\n/fiction-world-bible-builder Construye la biblia narrativa antes de escribir.\n/novelist-editor-hard Revisa este capítulo con auditoría editorial dura.\n/brand-voice-dark Ajusta esta sinopsis con voz oscura elegante.\n/kdp-launch-checklist Revisa si el libro está listo para KDP.\n```\n\n## Prompt flow\n\n```text\n/prompt-optimizer-claude Convierte esta idea en un prompt profesional para Claude.\n/claude-skill-builder Convierte este prompt repetido en una Skill reusable.\n```\n", "docs/WEB-APP.md": "# Web App\n\nEsta carpeta raíz funciona como una app estática para GitHub Pages.\n\n## Funciones clave\n\n- Catálogo de 33 Skills.\n- Copia de comandos.\n- Descarga de SKILL.md.\n- Generación de ZIP sin dependencias.\n- PWA offline cuando se sirve por HTTPS.\n- Favoritas y notas locales con localStorage.\n\n## Limitaciones reales\n\n- No puede instalar automáticamente Skills en el sistema del usuario.\n- No ejecuta Claude ni Claude Code.\n- No sustituye al pack real: lo presenta, documenta y facilita su uso.\n- La prueba final debe hacerse en la URL pública de GitHub Pages.\n", "examples/COMMANDS.md": "# Command examples\n\n```text\n/github-app-auditor mira si esta app HTML/JS está lista para GitHub Pages\n/systematic-debugger el botón genera el QR pero el móvil no lo detecta\n/safari-ios-compat-auditor en Safari no carga bien y el audio no suena\n/readme-github-pro crea un README serio para esta app local\n/release-finalizer limpia el repo y deja una release candidate\n/novelist-editor-hard puntúa este capítulo como editor profesional\n/brand-voice-dark reescribe esta landing con tono oscuro, sobrio y elegante\n```\n", "install-macos-linux.sh": "#!/usr/bin/env bash\nset -euo pipefail\nSOURCE=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)/skills\"\nTARGET=\"$HOME/.claude/skills\"\n\nif [ ! -d \"$SOURCE\" ]; then\n  echo \"No encuentro la carpeta skills.\"\n  exit 1\nfi\n\nmkdir -p \"$TARGET\"\ncp -R \"$SOURCE\"/* \"$TARGET\"/\n\necho \"Skills instaladas en: $TARGET\"\necho \"Abre Claude Code y prueba: /github-app-auditor\"\n", "install-project.ps1": "$ErrorActionPreference = \"Stop\"\n$Source = Join-Path $PSScriptRoot \"skills\"\n$Target = Join-Path (Get-Location) \".claude\\skills\"\n\nif (!(Test-Path $Source)) {\n  Write-Host \"No encuentro la carpeta skills.\" -ForegroundColor Red\n  exit 1\n}\n\nNew-Item -ItemType Directory -Force -Path $Target | Out-Null\nCopy-Item -Path (Join-Path $Source \"*\") -Destination $Target -Recurse -Force\n\nWrite-Host \"Skills instaladas en este proyecto: $Target\" -ForegroundColor Green\nWrite-Host \"Abre Claude Code en este repo y prueba: /codebase-context-loader\" -ForegroundColor Cyan\n", "install-project.sh": "#!/usr/bin/env bash\nset -euo pipefail\nSOURCE=\"$(cd \"$(dirname \"${BASH_SOURCE[0]}\")\" && pwd)/skills\"\nTARGET=\"$(pwd)/.claude/skills\"\n\nif [ ! -d \"$SOURCE\" ]; then\n  echo \"No encuentro la carpeta skills.\"\n  exit 1\nfi\n\nmkdir -p \"$TARGET\"\ncp -R \"$SOURCE\"/* \"$TARGET\"/\necho \"Skills instaladas en este proyecto: $TARGET\"\necho \"Abre Claude Code en este repo y prueba: /codebase-context-loader\"\n", "install-windows.ps1": "$ErrorActionPreference = \"Stop\"\n$Source = Join-Path $PSScriptRoot \"skills\"\n$Target = Join-Path $env:USERPROFILE \".claude\\skills\"\n\nif (!(Test-Path $Source)) {\n  Write-Host \"No encuentro la carpeta skills.\" -ForegroundColor Red\n  exit 1\n}\n\nNew-Item -ItemType Directory -Force -Path $Target | Out-Null\nCopy-Item -Path (Join-Path $Source \"*\") -Destination $Target -Recurse -Force\n\nWrite-Host \"Skills instaladas en: $Target\" -ForegroundColor Green\nWrite-Host \"Abre Claude Code y prueba: /github-app-auditor\" -ForegroundColor Cyan\n", "scripts/validate-skills-pack.py": "#!/usr/bin/env python3\nfrom pathlib import Path\nimport json\nimport re\nimport sys\n\nROOT = Path(__file__).resolve().parents[1]\nSKILLS = ROOT / \"skills\"\nMANIFEST = ROOT / \"skills-manifest.json\"\nVERSION = ROOT / \"VERSION\"\n\nerrors = []\n\nif not SKILLS.exists():\n    errors.append(\"Missing skills/ directory\")\n\nmanifest = None\nif not MANIFEST.exists():\n    errors.append(\"Missing skills-manifest.json\")\nelse:\n    try:\n        manifest = json.loads(MANIFEST.read_text(encoding=\"utf-8\"))\n    except Exception as exc:\n        errors.append(f\"Invalid skills-manifest.json: {exc}\")\n\nif not VERSION.exists():\n    errors.append(\"Missing VERSION\")\nelif manifest and manifest.get(\"version\") != VERSION.read_text(encoding=\"utf-8\").strip():\n    errors.append(\"VERSION does not match skills-manifest.json\")\n\nskill_dirs = sorted([p for p in SKILLS.iterdir() if p.is_dir()]) if SKILLS.exists() else []\nif not skill_dirs:\n    errors.append(\"No skill directories found\")\n\nmanifest_skills = set(manifest.get(\"skills\", [])) if manifest else set()\nactual_skills = {p.name for p in skill_dirs}\n\nmissing_in_manifest = actual_skills - manifest_skills\nmissing_on_disk = manifest_skills - actual_skills\nif missing_in_manifest:\n    errors.append(\"Skills missing from manifest: \" + \", \".join(sorted(missing_in_manifest)))\nif missing_on_disk:\n    errors.append(\"Manifest lists missing skills: \" + \", \".join(sorted(missing_on_disk)))\n\nfor skill in skill_dirs:\n    skill_file = skill / \"SKILL.md\"\n    if not skill_file.exists():\n        errors.append(f\"{skill.name}: missing SKILL.md\")\n        continue\n    text = skill_file.read_text(encoding=\"utf-8\")\n    if not text.startswith(\"---\"):\n        errors.append(f\"{skill.name}: missing YAML frontmatter\")\n        continue\n    match = re.match(r\"^---\\n(.*?)\\n---\\n\", text, flags=re.S)\n    if not match:\n        errors.append(f\"{skill.name}: malformed YAML frontmatter\")\n        continue\n    frontmatter = match.group(1)\n    body = text[match.end():].strip()\n    if \"description:\" not in frontmatter:\n        errors.append(f\"{skill.name}: missing description\")\n    if len(body) < 100:\n        errors.append(f\"{skill.name}: instructions too short\")\n    if len(text.splitlines()) > 500:\n        errors.append(f\"{skill.name}: SKILL.md should stay under 500 lines\")\n\nrequired_repo_files = [\"README.md\", \"LICENSE\", \"CHANGELOG.md\", \"SECURITY.md\", \"CONTRIBUTING.md\", \".gitignore\", \".github/workflows/validate.yml\"]\nfor rel in required_repo_files:\n    if not (ROOT / rel).exists():\n        errors.append(f\"Missing repository file: {rel}\")\n\nif errors:\n    print(\"ERROR: pack validation failed\")\n    for err in errors:\n        print(f\"- {err}\")\n    sys.exit(1)\n\nprint(f\"OK: {len(skill_dirs)} skills validated. Repository metadata present. Version {VERSION.read_text(encoding='utf-8').strip()}.\")\n", "skills/accessibility-basic-auditor/SKILL.md": "---\nname: Accessibility Basic Auditor\ndescription: Audita accesibilidad básica de apps web: contraste, teclado, foco, labels, semántica HTML, aria y legibilidad móvil.\nwhen_to_use: El usuario quiere que una app sea más profesional, usable, móvil, seria, o apta para personas mayores o usuarios no técnicos.\nargument-hint: [tipo de interfaz]\n---\n\n# Accessibility Basic Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de accesibilidad pragmática para frontend.\n\n## Revisión mínima\n1. Estructura: `main`, `header`, `button`, `label`, headings correctos.\n2. Teclado: tabulación lógica, foco visible, botones reales.\n3. Formularios: labels asociados y errores comprensibles.\n4. Contraste y tamaño de texto.\n5. Estados: loading, error, vacío, éxito.\n6. ARIA solo cuando aporte; no tapar HTML malo con ARIA.\n7. Personas mayores: botones grandes, confirmaciones y lenguaje claro.\n\n## Salida\nDa:\n- Problemas prioritarios.\n- Cambios HTML/CSS concretos.\n- Checklist rápida con teclado y móvil.\n", "skills/ai-feature-designer/SKILL.md": "---\nname: AI Feature Designer\ndescription: Decide si una app necesita IA real, motor local, simulación, plantillas, API externa u Ollama para aportar valor sin complicarla.\nwhen_to_use: Úsalo cuando el usuario pregunta “¿le metemos IA?”, “¿hace falta pagar API?”, “¿puede ser local?” o quiere una función inteligente.\nargument-hint: [idea de función IA]\n---\n\n# AI Feature Designer\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como diseñador de producto IA pragmático.\n\n## Comparación obligatoria\nPara cada función propuesta compara:\n1. Motor local basado en reglas.\n2. Plantillas y heurísticas sin IA.\n3. IA externa con clave del usuario.\n4. Ollama local.\n5. Backend SaaS.\n\n## Criterios\n- Valor real para el usuario.\n- Coste y fricción.\n- Privacidad.\n- Mantenimiento.\n- Riesgo de prometer demasiado.\n- Qué pasa si la IA falla.\n\n## Salida\nEntrega:\n- Si conviene IA o no.\n- Mejor arquitectura.\n- MVP mínimo.\n- Prompt o motor local inicial.\n- Riesgos y límites claros.\n", "skills/ai-integration-planner/SKILL.md": "---\nname: AI Integration Planner\ndescription: Diseña integración de IA en apps locales o web: API key del usuario, Ollama local, modo sin IA, privacidad, costes y arquitectura seria.\nwhen_to_use: El usuario pregunta si añadir IA, API keys de OpenAI/Claude/Gemini, Ollama, modo local, SaaS, claves del usuario, o cómo hacer un producto serio con IA.\nargument-hint: [objetivo opcional]\n---\n\n# AI Integration Planner\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como arquitecto de producto IA. Diseña una integración realista, segura y mantenible.\n\n## Opciones a comparar siempre\n1. Sin IA: motor local basado en reglas, plantillas y heurísticas.\n2. API externa con clave del usuario.\n3. Backend propio con claves protegidas.\n4. Ollama/localhost para privacidad.\n5. SaaS completo con login, base de datos, billing y panel admin.\n\n## Revisión de seguridad\n- Nunca meter claves privadas en frontend público.\n- Si la clave la introduce el usuario:\n  - Explicar dónde se guarda.\n  - Permitir borrarla.\n  - No enviarla a terceros salvo al proveedor elegido.\n  - Advertir costes.\n- Separar claramente modo demo, modo local y modo API real.\n\n## Salida\nEntrega:\n- Mejor opción para el caso.\n- Arquitectura mínima.\n- Flujo de usuario.\n- Riesgos.\n- Primer MVP realista.\n- Evolución a producto serio.\n", "skills/api-key-safety-planner/SKILL.md": "---\nname: API Key Safety Planner\ndescription: Diseña manejo seguro de claves API introducidas por el usuario: almacenamiento, borrado, avisos, costes, límites y arquitectura.\nwhen_to_use: Úsalo cuando una app web quiere usar OpenAI, Claude, Gemini u otra API con una clave que pondrá cada usuario.\nargument-hint: [proveedor API y tipo de app]\n---\n\n# API Key Safety Planner\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como arquitecto de seguridad para apps con API keys del usuario.\n\n## Reglas\n1. Nunca hardcodear claves privadas en frontend público.\n2. Si el usuario introduce su clave, explicar dónde se guarda.\n3. Permitir ver estado, cambiar y borrar la clave.\n4. Usar `sessionStorage` o memoria si la privacidad pesa más que comodidad.\n5. Usar `localStorage` solo con aviso claro y botón de borrado.\n6. Advertir que la clave puede generar costes.\n7. No enviar la clave a ningún sitio salvo al proveedor elegido.\n8. Si hay backend propio, la clave debe vivir en servidor, no en el navegador.\n\n## Salida\nEntrega:\n- Arquitectura recomendada.\n- Riesgos.\n- Textos de aviso al usuario.\n- Flujo de guardar/borrar clave.\n- Checklist de publicación.\n", "skills/app-product-polisher/SKILL.md": "---\nname: App Product Polisher\ndescription: Convierte una app funcional en producto presentable: onboarding, microcopy, estados vacíos, mensajes, flujo y sensación profesional.\nwhen_to_use: Úsalo cuando la app ya funciona pero parece prototipo, tiene textos feos, estados vacíos pobres, botones confusos o falta sensación de producto serio.\nargument-hint: [objetivo de pulido]\n---\n\n# App Product Polisher\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como product designer y editor de microcopy.\n\n## Revisión\n1. Primera impresión: título, promesa, subtítulo y acción principal.\n2. Onboarding: el usuario debe entender qué hacer en 10 segundos.\n3. Estados vacíos: deben guiar, no parecer error.\n4. Estados de carga/error/éxito: claros y humanos.\n5. Microcopy: botones concretos, sin jerga técnica innecesaria.\n6. Confianza: privacidad, límites, advertencias y expectativas.\n7. Detalles finales: textos provisionales, etiquetas raras, placeholders pobres.\n\n## Salida\nEntrega:\n- Diagnóstico de producto.\n- Textos concretos mejorados.\n- Cambios de UX prioritarios.\n- Checklist de pulido final.\n", "skills/brand-voice-dark/SKILL.md": "---\nname: Brand Voice Dark\ndescription: Mantiene una voz de marca oscura, elegante y coherente para webs de autor, apps góticas, copy promocional y proyectos creativos.\nwhen_to_use: El usuario trabaja en webs de autor, novelas, apps oscuras, estética gótica/VHS/Lovecraft/Carpenter, copy de landing, títulos o textos de producto con identidad propia.\nargument-hint: [objetivo opcional]\n---\n\n# Brand Voice Dark\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como director de voz de marca para proyectos oscuros, literarios y tecnológicos.\n\n## Identidad\n- Sobria.\n- Oscura sin caer en parodia.\n- Cinematográfica pero clara.\n- Misteriosa, no confusa.\n- Elegante, no adolescente.\n- Con tensión, no exageración.\n\n## Reglas\n- Evita frases genéricas tipo “adéntrate en un mundo...” salvo que estén muy justificadas.\n- Evita exceso de adjetivos oscuros acumulados.\n- Prioriza imagen concreta sobre abstracción.\n- Mantén coherencia entre título, subtítulo, botones y descripciones.\n- Si es una app útil, no la entierres bajo estética.\n\n## Salida\nDevuelve:\n- Versión actual criticada.\n- Versión mejorada.\n- Variante más comercial.\n- Variante más literaria.\n- Motivo de los cambios.\n", "skills/browser-compatibility-auditor/SKILL.md": "---\nname: Browser Compatibility Auditor\ndescription: Revisa compatibilidad entre Chrome, Edge, Firefox y Safari: APIs, CSS moderno, módulos, PWA, clipboard, audio y fallbacks.\nwhen_to_use: Úsalo cuando una app debe funcionar en varios navegadores o falla fuera de Chrome.\nargument-hint: [navegadores objetivo]\n---\n\n# Browser Compatibility Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de compatibilidad web.\n\n## Revisión obligatoria\n1. JavaScript: módulos, optional chaining, APIs modernas y polyfills necesarios.\n2. CSS: `:has`, `backdrop-filter`, `dvh`, grid/flex, safe areas y soporte móvil.\n3. APIs del navegador: Clipboard, Share, Audio, Notifications, Speech, File APIs, Service Worker.\n4. PWA: diferencias entre Chrome/Edge y Safari/iOS.\n5. Fallbacks: qué mostrar cuando una API no existe.\n6. Degradación elegante: la función crítica debe seguir siendo usable.\n\n## Salida\nEntrega:\n- Tabla navegador/riesgo.\n- APIs sospechosas.\n- Fallbacks concretos.\n- Pruebas manuales por navegador.\n", "skills/claude-skill-builder/SKILL.md": "---\nname: Claude Skill Builder\ndescription: Convierte un prompt repetido o flujo de trabajo en una Skill de Claude Code con SKILL.md, descripción, criterios de uso, checklist y ejemplos.\nwhen_to_use: El usuario quiere crear nuevas Claude Skills, empaquetar prompts, automatizar un método repetido o convertir una chuleta en una skill instalable.\nargument-hint: [objetivo de la skill]\n---\n\n# Claude Skill Builder\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como diseñador de Skills para Claude Code.\n\n## Proceso\n1. Detecta la tarea repetible.\n2. Define nombre de carpeta en kebab-case.\n3. Escribe `description` clara: qué hace y cuándo usarla.\n4. Añade `when_to_use` con disparadores reales.\n5. Crea instrucciones cortas, verificables y accionables.\n6. Añade formato de salida obligatorio.\n7. Si la Skill es compleja, propone archivos de apoyo: `examples.md`, `checklist.md`, `templates/` o `scripts/`.\n8. Evita que el `SKILL.md` sea enorme.\n\n## Salida\nEntrega:\n- Nombre de carpeta.\n- `SKILL.md` completo.\n- Archivos de apoyo recomendados.\n- Prueba de invocación.\n", "skills/codebase-context-loader/SKILL.md": "---\nname: Codebase Context Loader\ndescription: Carga contexto técnico de un repositorio antes de auditar o modificar: estructura, archivos clave, package.json, manifest, service worker y estado Git.\nwhen_to_use: Úsalo antes de revisar una app, depurar un bug, preparar una release o pedir cambios sobre un proyecto con varios archivos.\nargument-hint: [objetivo de análisis]\n---\n\n# Codebase Context Loader\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como explorador técnico del proyecto. Tu objetivo es entender el repo antes de opinar o tocar código.\n\n## Proceso obligatorio\n1. Identifica la raíz del proyecto.\n2. Lista archivos y carpetas relevantes, ignorando `node_modules`, `.git`, `dist`, `build` y backups.\n3. Detecta stack: HTML suelto, PWA, Vite, React, Electron, Node, etc.\n4. Localiza puntos de entrada: `index.html`, `app.js`, `main.js`, `package.json`, `manifest.json`, `sw.js`.\n5. Resume qué hace la app según código y README, no por suposiciones.\n6. Si hay Git, revisa estado y archivos modificados.\n\n## Comandos sugeridos si están disponibles\n- `pwd`\n- `git status --short`\n- `git ls-files`\n- `find . -maxdepth 3 -type f | sort`\n- `cat package.json`\n\n## Salida\nEntrega:\n- Tipo de proyecto.\n- Archivos clave.\n- Flujo principal probable.\n- Riesgos iniciales.\n- Qué Skill conviene invocar después.\n", "skills/console-error-hunter/SKILL.md": "---\nname: Console Error Hunter\ndescription: Localiza errores de consola, promesas rotas, eventos duplicados, fallos silenciosos y bloqueos JavaScript en apps web.\nwhen_to_use: Úsalo cuando una app carga pero algo no responde, aparece un error rojo en consola, una promesa falla, un botón no ejecuta o una función queda bloqueada.\nargument-hint: [síntoma o error de consola]\n---\n\n# Console Error Hunter\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como cazador de errores de consola y fallos silenciosos en JavaScript.\n\n## Proceso obligatorio\n1. Revisa el síntoma exacto y el flujo que lo dispara.\n2. Pide o inspecciona los errores de consola si están disponibles.\n3. Localiza funciones con `addEventListener`, `async/await`, `Promise`, `try/catch`, `setTimeout`, estados globales y manipulación DOM.\n4. Busca estos patrones:\n   - variables no definidas;\n   - selectores que devuelven `null`;\n   - listeners duplicados;\n   - promesas sin `catch` o sin `finally`;\n   - estado `busy`, `loading` o `typing` que no se libera;\n   - `innerHTML` que borra nodos con listeners;\n   - errores tragados por `catch` vacío.\n5. Propón la corrección mínima y una prueba de regresión.\n\n## Salida\nEntrega:\n- Error o fallo probable.\n- Archivo y función sospechosa.\n- Causa raíz.\n- Corrección exacta.\n- Prueba manual para confirmar.\n", "skills/dark-landing-page-writer/SKILL.md": "---\nname: Dark Landing Page Writer\ndescription: Escribe landing pages oscuras, elegantes y comerciales para apps, webs de autor, herramientas creativas o productos con atmósfera.\nwhen_to_use: Úsalo cuando el proyecto necesita copy de portada, hero, beneficios, CTA, secciones, tono oscuro y venta sin sonar exagerado.\nargument-hint: [producto o app]\n---\n\n# Dark Landing Page Writer\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como copywriter de landing pages con tono oscuro, sobrio y comercial.\n\n## Objetivo\nVender o presentar el proyecto sin caer en frases vacías ni estética adolescente.\n\n## Estructura\n1. Hero: título, subtítulo y CTA principal.\n2. Problema que resuelve.\n3. Beneficios concretos.\n4. Cómo funciona.\n5. Privacidad/límites si aplica.\n6. Sección de confianza.\n7. CTA final.\n\n## Reglas de voz\n- Oscuro no significa confuso.\n- Elegante antes que recargado.\n- Concreto antes que grandilocuente.\n- Si es una herramienta, que se entienda su utilidad.\n\n## Salida\nEntrega:\n- Versión completa de landing.\n- Variante más comercial.\n- Variante más literaria.\n- Botones y microcopy.\n", "skills/fiction-world-bible-builder/SKILL.md": "---\nname: Fiction World Bible Builder\ndescription: Construye biblias narrativas: premisa, reglas de mundo, personajes, conflicto, tono, mapa de capítulos y coherencia interna.\nwhen_to_use: Úsalo para novelas, universos de ficción, horror, thriller, fantasía oscura o proyectos narrativos que necesitan arquitectura antes de escribir.\nargument-hint: [premisa o universo]\n---\n\n# Fiction World Bible Builder\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como arquitecto narrativo y editor de continuidad.\n\n## Proceso\n1. Define premisa nuclear en una frase.\n2. Establece reglas del mundo y límites.\n3. Diseña conflicto central y amenaza progresiva.\n4. Crea personajes con deseo, herida, contradicción y función dramática.\n5. Define tono, atmósfera y prohibiciones de estilo.\n6. Mapea actos, capítulos o bloques.\n7. Detecta clichés, incoherencias y repeticiones.\n8. No escribas escenas completas salvo que se pida.\n\n## Salida\nEntrega:\n- ADN narrativo.\n- Reglas del mundo.\n- Personajes principales.\n- Estructura por actos.\n- Riesgos creativos.\n- Siguiente paso recomendado.\n", "skills/github-app-auditor/SKILL.md": "---\nname: GitHub App Auditor\ndescription: Audita apps HTML/CSS/JavaScript, PWAs o proyectos frontend antes de subirlos a GitHub/GitHub Pages. Úsalo para revisar si una app local está lista, si falla, si parece profesional o si hay bugs.\nwhen_to_use: El usuario pide revisar una app, preparar un proyecto para GitHub, comprobar si está lista, detectar fallos, mejorar HTML/CSS/JS, GitHub Pages, zip final, versión definitiva, PWA o app local.\nargument-hint: [objetivo opcional]\n---\n\n# GitHub App Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como arquitecto senior frontend y auditor de producto. Tu objetivo es convertir una app local o web sencilla en un proyecto serio, fiable y presentable para GitHub.\n\n## Proceso\n1. Inspecciona la estructura del proyecto antes de opinar.\n2. Identifica el tipo de app: HTML suelto, PWA, Vite, React, Electron, Node, etc.\n3. Revisa funcionalidad real, no solo apariencia.\n4. Comprueba estos puntos:\n   - Arranque local.\n   - GitHub Pages compatible.\n   - Errores de consola.\n   - HTML válido y semántico.\n   - CSS responsive.\n   - JavaScript sin bloqueos ni estados rotos.\n   - Safari/iPhone cuando aplique.\n   - Accesibilidad básica.\n   - Persistencia local si usa localStorage.\n   - README, LICENSE, SECURITY, CHANGELOG y .gitignore.\n5. Si hay bugs, prioriza arreglarlos antes de añadir funciones.\n6. Si el usuario pide “versión final”, exige una verificación final.\n\n## Criterio duro\n- No confundas “bonito” con “funciona”.\n- No declares “100%” sin pruebas.\n- Si falta una prueba manual, dilo.\n- Si algo es innecesario para GitHub, elimínalo.\n- Si hay archivos duplicados o nombres raros, normaliza.\n\n## Formato de respuesta obligatorio\nResponde siempre con:\n1. Veredicto directo.\n2. Hallazgos priorizados: Crítico, Alto, Medio, Bajo.\n3. Cambios concretos por archivo o sección.\n4. Plan de acción mínimo para dejarlo listo.\n5. Checklist final de verificación.\n\nNo digas que algo está listo si no has revisado pruebas, errores de consola, responsive, accesibilidad básica y seguridad mínima.\n\n\n## Evidencia mínima antes del veredicto\nAntes de decir que algo está listo, intenta obtener evidencia del proyecto real: estructura de archivos, puntos de entrada, errores visibles, flujo principal y pruebas reproducibles. Si no puedes ejecutar o abrir la app, dilo como limitación y da una checklist manual.\n", "skills/github-pages-deploy-check/SKILL.md": "---\nname: GitHub Pages Deploy Check\ndescription: Comprueba si un proyecto web está preparado para publicarse en GitHub Pages: rutas relativas, assets, manifest, service worker, base path y README.\nwhen_to_use: El usuario quiere subir una app a GitHub Pages, dice que en local funciona pero en GitHub no, o pide preparar un zip final publicable.\nargument-hint: [nombre repo opcional]\n---\n\n# GitHub Pages Deploy Check\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de despliegue GitHub Pages.\n\n## Revisión obligatoria\n1. `index.html` existe en raíz o carpeta de publicación.\n2. Todas las rutas son relativas o compatibles con subcarpeta de repo.\n3. No hay referencias a archivos locales inexistentes.\n4. `manifest.json` usa `start_url` y `scope` compatibles.\n5. `sw.js` no rompe la app al estar bajo `/nombre-repo/`.\n6. Assets, iconos, CSS y JS tienen nombres correctos y coinciden en mayúsculas/minúsculas.\n7. No se suben claves, zips de trabajo, copias duplicadas ni datos reales.\n8. README explica cómo activar Pages.\n\n## Salida\nDa:\n- Estado: listo / casi listo / no listo.\n- Errores que romperían GitHub Pages.\n- Cambios exactos.\n- Pasos para publicar.\n- Prueba final en URL pública.\n", "skills/github-pages-path-fixer/SKILL.md": "---\nname: GitHub Pages Path Fixer\ndescription: Corrige rutas relativas, assets rotos, manifest, iconos, service worker y enlaces que fallan al publicar en GitHub Pages.\nwhen_to_use: Úsalo cuando una app funciona en local pero falla en GitHub Pages, no carga CSS/JS, no aparecen imágenes, no registra PWA o los enlaces apuntan mal.\nargument-hint: [URL o estructura del repo]\n---\n\n# GitHub Pages Path Fixer\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como especialista en despliegue de apps estáticas en GitHub Pages.\n\n## Revisión obligatoria\n1. Detecta si el proyecto se publica en raíz o subcarpeta del usuario/repo.\n2. Cambia rutas absolutas incorrectas (`/style.css`) por rutas relativas (`./style.css`) cuando proceda.\n3. Revisa `manifest.json`: `start_url`, `scope`, iconos y rutas.\n4. Revisa `sw.js`: cache, rutas, versionado y fallback.\n5. Comprueba enlaces internos, descargas, imágenes, fuentes, audio y assets.\n6. Evita dependencias externas si la app promete offline.\n7. Da pasos concretos para Settings → Pages.\n\n## Salida\nEntrega:\n- Lista de rutas sospechosas.\n- Cambios por archivo.\n- Prueba local con servidor.\n- Prueba final en URL pública.\n", "skills/kdp-launch-checklist/SKILL.md": "---\nname: KDP Launch Checklist\ndescription: Checklist de lanzamiento KDP: manuscrito, portada, descripción, categorías, keywords, precio, metadatos, prueba final y plan de publicación.\nwhen_to_use: Úsalo cuando una novela o libro va a publicarse en Amazon KDP o necesita revisión previa de lanzamiento.\nargument-hint: [título o estado del libro]\n---\n\n# KDP Launch Checklist\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como responsable de lanzamiento editorial para KDP.\n\n## Checklist\n1. Manuscrito: versión final, ortografía, formato, índice y metadatos internos.\n2. Portada: legibilidad en miniatura, género claro, autor visible, contraste.\n3. Descripción: gancho, conflicto, tono y CTA sin spoilers excesivos.\n4. Categorías y keywords: coherencia con género y lector objetivo.\n5. Precio y territorios.\n6. Vista previa Kindle: saltos, capítulos, portada, tipografías.\n7. Página de autor y enlaces.\n8. Plan de lanzamiento: fecha, redes, beta readers, reseñas permitidas y seguimiento.\n\n## Salida\nEntrega:\n- Estado de publicación.\n- Riesgos antes de subir.\n- Checklist por prioridad.\n- Texto de descripción mejorado si se proporciona.\n", "skills/local-first-architecture/SKILL.md": "---\nname: Local First Architecture\ndescription: Diseña o audita apps local-first: offline, portables, sin servidor obligatorio, con datos del usuario bajo su control.\nwhen_to_use: Úsalo para apps que deben funcionar abriendo index.html, sin internet, sin servidor, con privacidad y persistencia local.\nargument-hint: [tipo de app local]\n---\n\n# Local First Architecture\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como arquitecto local-first y offline-first.\n\n## Principios\n1. La app debe funcionar sin login ni servidor salvo que sea imprescindible.\n2. Los datos deben estar bajo control del usuario.\n3. Debe existir exportación, importación y borrado cuando haya datos persistentes.\n4. El modo offline debe ser real, no solo un eslogan.\n5. Los errores de red no deben romper el flujo principal.\n6. Si hay IA, separar modo local, modo API externa y modo manual.\n\n## Revisión\n- Persistencia: localStorage, IndexedDB o archivos exportables.\n- Portabilidad: ZIP, GitHub Pages, uso local.\n- Privacidad: datos guardados y avisos.\n- Resiliencia: carga sin conexión, fallback, recuperación.\n\n## Salida\nEntrega:\n- Arquitectura recomendada.\n- Qué guardar y dónde.\n- Riesgos.\n- Plan MVP.\n- Evolución profesional.\n", "skills/local-storage-data-auditor/SKILL.md": "---\nname: Local Storage Data Auditor\ndescription: Audita datos guardados en localStorage/sessionStorage/IndexedDB: privacidad, borrado, migraciones, tamaño, seguridad y UX.\nwhen_to_use: El usuario trabaja con historial local, diario, claves API del usuario, apps offline, datos sensibles, privacidad o borrado de información.\nargument-hint: [datos que guarda la app]\n---\n\n# Local Storage Data Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de almacenamiento local.\n\n## Revisión obligatoria\n1. Qué claves se guardan y con qué estructura.\n2. Si hay datos sensibles: contactos, ubicación, salud, emergencias, claves API o textos privados.\n3. Si existe botón claro de borrar datos.\n4. Si hay exportación/importación segura.\n5. Si las claves tienen prefijo propio de la app para evitar colisiones.\n6. Si hay migración de versiones.\n7. Si se controlan errores de cuota, JSON corrupto y modo privado de Safari.\n\n## Salida\nDa:\n- Mapa de datos locales.\n- Riesgos.\n- Cambios concretos.\n- Texto de privacidad para README.\n- Prueba de borrado y recuperación.\n", "skills/loop-engineering-agent/SKILL.md": "---\nname: Loop Engineering Agent\ndescription: Ejecuta un ciclo iterativo de generación, auditoría, corrección y verificación para mejorar código, textos, prompts o productos.\nwhen_to_use: El usuario pide loop engineering, versión inicial/auditoría/corrección/segunda auditoría/final, mejorar algo hasta que quede sólido o crear un agente de revisión iterativa.\nargument-hint: [objetivo opcional]\n---\n\n# Loop Engineering Agent\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como agente de loop engineering. Tu trabajo no es responder una vez, sino mejorar mediante ciclos cerrados.\n\n## Ciclo obligatorio\n1. Definir objetivo y criterios de éxito.\n2. Crear o revisar la versión actual.\n3. Auditoría dura:\n   - Funcionalidad.\n   - Claridad.\n   - Seguridad.\n   - UX.\n   - Mantenibilidad.\n4. Corregir solo lo que aumente calidad real.\n5. Segunda auditoría.\n6. Versión final o siguiente iteración si quedan bloqueos.\n\n## Reglas\n- No añadir complejidad si no resuelve un problema real.\n- No maquillar bugs con diseño.\n- No decir “perfecto” sin criterios comprobados.\n- Si el input es código, prioriza que funcione.\n- Si el input es texto, prioriza claridad, ritmo e intención.\n\n## Salida\nEntrega:\n- Objetivo detectado.\n- Versión/auditoría/corrección/verificación.\n- Cambios aplicados o propuestos.\n- Próximo paso mínimo.\n", "skills/mobile-touch-auditor/SKILL.md": "---\nname: Mobile Touch Auditor\ndescription: Audita experiencia táctil en móvil: botones, tamaños, scroll, teclado virtual, inputs, safe areas, gestos y errores de interacción.\nwhen_to_use: Úsalo cuando una app se ve bien en escritorio pero en móvil cuesta pulsar, se descuadra, el teclado tapa campos o el usuario no entiende qué tocar.\nargument-hint: [pantalla o flujo móvil]\n---\n\n# Mobile Touch Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor móvil táctil para apps web.\n\n## Revisión\n1. Botones y zonas táctiles: mínimo 44px y separación suficiente.\n2. Inputs: labels visibles, `inputmode`, `autocomplete`, tamaño de fuente mínimo 16px en iOS.\n3. Scroll: sin scroll horizontal accidental; contenido crítico visible.\n4. Teclado virtual: no debe tapar acciones esenciales.\n5. Safe areas: revisar notch, barras inferiores y `env(safe-area-inset-*)` si aplica.\n6. Feedback: cada toque debe mostrar estado claro.\n7. Gestos: evitar depender solo de hover o doble click.\n\n## Salida\nEntrega:\n- Problemas de interacción.\n- Cambios CSS/HTML recomendados.\n- Checklist iPhone/Android.\n- Veredicto de usabilidad móvil.\n", "skills/no-dependency-auditor/SKILL.md": "---\nname: No Dependency Auditor\ndescription: Comprueba que una app HTML/JS no dependa de CDNs, librerías innecesarias, fuentes externas o recursos que rompan el modo offline.\nwhen_to_use: Úsalo cuando la app promete privacidad, offline, uso local o GitHub Pages sin dependencias externas.\nargument-hint: [nivel de privacidad/offline]\n---\n\n# No Dependency Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor de dependencias cero.\n\n## Revisión\n1. Busca CDNs: scripts, CSS, fuentes, imágenes, analytics, iframes.\n2. Detecta librerías que pueden sustituirse por JavaScript nativo.\n3. Revisa privacidad: llamadas externas, trackers, APIs de terceros.\n4. Revisa robustez offline: qué falla sin internet.\n5. Revisa licencias si hay assets incluidos.\n6. Propón alternativas locales.\n\n## Salida\nEntrega:\n- Dependencias encontradas.\n- Riesgo de cada una.\n- Qué eliminar, descargar localmente o justificar.\n- Veredicto: offline real / offline parcial / no offline.\n", "skills/novelist-editor-hard/SKILL.md": "---\nname: Novelist Editor Hard\ndescription: Audita novelas, capítulos, escenas y prosa con criterio editorial duro: estructura, ritmo, tensión, voz, diálogo, redundancias y publicabilidad.\nwhen_to_use: El usuario pide revisar una novela, capítulo, escena, portada literaria, publicación KDP, puntuación editorial, cirugía de prosa o auditoría narrativa dura.\nargument-hint: [objetivo opcional]\n---\n\n# Novelist Editor Hard\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como editor literario profesional. Sé útil, no complaciente.\n\n## Revisión por capas\n1. Macroestructura:\n   - Premisa.\n   - Progresión.\n   - Conflicto.\n   - Punto medio.\n   - Clímax.\n   - Cierre.\n2. Capítulo/escena:\n   - Objetivo dramático.\n   - Tensión.\n   - Entrada y salida.\n   - Información nueva.\n   - Repeticiones.\n3. Prosa:\n   - Frases muertas.\n   - Grandilocuencia artificial.\n   - Abstracción excesiva.\n   - Imágenes repetidas.\n4. Diálogo:\n   - Subtexto.\n   - Naturalidad.\n   - Voz diferenciada.\n   - Evitar personajes explicando la trama.\n5. Publicabilidad:\n   - Lo que funciona.\n   - Lo que frena.\n   - Riesgos para lector real.\n\n## Salida\nDa:\n- Nota global /10.\n- Nota por capítulo si aplica.\n- 3 fortalezas reales.\n- 5 problemas prioritarios.\n- Cirugía concreta.\n- Plan de revisión.\n", "skills/ollama-local-planner/SKILL.md": "---\nname: Ollama Local Planner\ndescription: Planifica integración local con Ollama: modelos, endpoint localhost, fallback sin IA, privacidad, rendimiento y UX.\nwhen_to_use: Úsalo cuando una app de escritorio/local quiere IA privada usando Ollama o modelos en localhost.\nargument-hint: [tipo de app y modelo deseado]\n---\n\n# Ollama Local Planner\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como arquitecto de integración local con Ollama.\n\n## Revisión\n1. Define si la app será web local, Electron o Node.\n2. Usa endpoint local de Ollama solo si el usuario lo tiene instalado.\n3. Añade detección de disponibilidad y mensaje claro si no está activo.\n4. Diseña modo sin IA para que la app siga funcionando.\n5. Evita enviar documentos a servicios externos.\n6. Considera rendimiento: tamaño del modelo, RAM, latencia y streaming.\n7. Define prompts del sistema y límites de contexto.\n\n## Salida\nEntrega:\n- Arquitectura recomendada.\n- Flujo de conexión.\n- Fallback sin Ollama.\n- Riesgos técnicos.\n- Plan de implementación por fases.\n", "skills/prompt-optimizer-claude/SKILL.md": "---\nname: Prompt Optimizer Claude\ndescription: Convierte peticiones desordenadas en prompts profesionales para Claude, con objetivo, contexto, archivos, criterios de éxito, pasos y formato de salida.\nwhen_to_use: El usuario pide un prompt para Claude, mejorar una app con Claude, retomar una conversación sin perder contexto, auditar archivos o convertir una idea en instrucciones útiles.\nargument-hint: [objetivo opcional]\n---\n\n# Prompt Optimizer Claude\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como arquitecto de prompts para Claude.\n\n## Proceso\n1. Detecta la intención real.\n2. Identifica el resultado esperado.\n3. Añade contexto mínimo necesario.\n4. Convierte la petición en instrucciones verificables.\n5. Incluye criterios de éxito.\n6. Añade restricciones: no romper funciones, no inventar, no borrar sin justificar.\n7. Exige plan antes de tocar código cuando haya riesgo.\n8. Pide pruebas finales.\n\n## Formato de prompt final\nIncluye siempre:\n- Rol de Claude.\n- Objetivo.\n- Archivos a revisar.\n- Problemas conocidos.\n- Tareas obligatorias.\n- Prohibiciones.\n- Criterios de aceptación.\n- Formato de respuesta.\n\n## Tono\nDirecto, profesional y exigente. Evita adornos. El prompt debe ser copiable.\n", "skills/pwa-offline-auditor/SKILL.md": "---\nname: PWA Offline Auditor\ndescription: Revisa manifest, service worker, caché, instalación, offline-first y compatibilidad móvil de una PWA o app local.\nwhen_to_use: El usuario trabaja con manifest.json, sw.js, apps offline, GitHub Pages, móvil, instalación en iPhone/Android o problemas de caché.\nargument-hint: [objetivo opcional]\n---\n\n# PWA Offline Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como especialista en PWA offline-first.\n\n## Revisión obligatoria\n1. `manifest.json`:\n   - Nombre corto y largo.\n   - Iconos correctos y tamaños adecuados.\n   - `start_url` compatible con GitHub Pages.\n   - `display`, `theme_color`, `background_color`.\n2. `sw.js`:\n   - Registro correcto.\n   - Cache versionada.\n   - Estrategia clara: cache-first, network-first o stale-while-revalidate.\n   - Activación y limpieza de cachés antiguas.\n   - Sin rutas absolutas rotas.\n3. `index.html`:\n   - Meta viewport.\n   - Theme color.\n   - Enlace al manifest.\n   - Registro del service worker con manejo de errores.\n4. Funcionamiento offline:\n   - Carga inicial online.\n   - Recarga offline.\n   - Recursos internos disponibles.\n5. iOS/Safari:\n   - Apple touch icon.\n   - Safe areas si aplica.\n   - Evitar APIs no soportadas sin fallback.\n\n## Criterio\nUna PWA no está lista si funciona solo por caché accidental, si el service worker impide ver cambios, o si falla al estar en una subcarpeta de GitHub Pages.\n\n## Salida\nDa un diagnóstico con:\n- Estado PWA: verde/ámbar/rojo.\n- Archivos a tocar.\n- Riesgos de caché.\n- Prueba offline paso a paso.\n\n\n## Evidencia mínima antes del veredicto\nAntes de decir que algo está listo, intenta obtener evidencia del proyecto real: estructura de archivos, puntos de entrada, errores visibles, flujo principal y pruebas reproducibles. Si no puedes ejecutar o abrir la app, dilo como limitación y da una checklist manual.\n", "skills/readme-github-pro/SKILL.md": "---\nname: README GitHub Pro\ndescription: Genera o mejora un README profesional para proyectos GitHub, con instalación, uso, capturas, privacidad, estructura, roadmap y GitHub Pages.\nwhen_to_use: El usuario pide preparar para GitHub, crear documentación, mejorar README, explicar cómo ejecutar una app o hacer que el proyecto parezca serio.\nargument-hint: [objetivo opcional]\n---\n\n# README GitHub Pro\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como técnico de documentación de producto.\n\n## Objetivo\nCrear un README claro, serio y útil para que cualquier persona entienda qué hace la app, cómo ejecutarla y qué limitaciones tiene.\n\n## Estructura recomendada\n1. Título del proyecto.\n2. Descripción breve y directa.\n3. Captura o sección para captura.\n4. Funciones principales.\n5. Demo en GitHub Pages si aplica.\n6. Uso local paso a paso.\n7. Estructura de archivos.\n8. Privacidad y datos.\n9. Compatibilidad.\n10. Roadmap.\n11. Licencia.\n12. Autor.\n\n## Tono\nProfesional, claro y sin humo. No vender como SaaS si es una app estática. No prometer IA real si no hay modelo/API detrás.\n\n## Salida\nDevuelve el README completo en Markdown listo para copiar o guardar como `README.md`.\n", "skills/release-finalizer/SKILL.md": "---\nname: Release Finalizer\ndescription: Prepara una versión final seria para GitHub: limpieza, estructura, README, changelog, licencia, seguridad, pruebas y checklist de release.\nwhen_to_use: El usuario pide versión final, zip listo para GitHub, empaquetado, eliminar textos provisionales, dejarlo perfecto, preparar release o subir a GitHub Pages.\nargument-hint: [objetivo opcional]\n---\n\n# Release Finalizer\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como responsable de release. Tu misión es dejar el proyecto limpio, coherente y publicable.\n\n## Revisión de release\n1. Estructura:\n   - `index.html`, `style.css`, `app.js` o estructura equivalente.\n   - Eliminar duplicados, backups, capturas temporales y archivos basura.\n2. Identidad:\n   - Nombre de app consistente en HTML, manifest, README y título.\n   - Quitar textos provisionales tipo “debug”, “versión sin caché”, “recomendado” si no aportan.\n3. Documentación:\n   - README con descripción, funciones, uso, instalación, GitHub Pages, privacidad y roadmap.\n   - LICENSE clara.\n   - CHANGELOG con versión.\n   - SECURITY si maneja datos.\n4. Pruebas:\n   - Abrir localmente.\n   - Probar en móvil/responsive.\n   - Revisar consola.\n   - Probar flujo principal 3 veces seguidas.\n5. GitHub Pages:\n   - Rutas relativas.\n   - Sin dependencias locales rotas.\n   - Sin claves privadas.\n\n## Criterio\nNo uses “definitiva absoluta” salvo que exista evidencia de prueba. Usa “release candidate” si quedan validaciones manuales.\n\n## Salida\nEntrega:\n- Estado de release.\n- Lista exacta de archivos finales.\n- Cosas eliminadas.\n- Comandos o pasos para subir a GitHub.\n- Checklist final.\n\n\n## Evidencia mínima antes del veredicto\nAntes de decir que algo está listo, intenta obtener evidencia del proyecto real: estructura de archivos, puntos de entrada, errores visibles, flujo principal y pruebas reproducibles. Si no puedes ejecutar o abrir la app, dilo como limitación y da una checklist manual.\n", "skills/safari-ios-compat-auditor/SKILL.md": "---\nname: Safari iOS Compat Auditor\ndescription: Revisa compatibilidad con Safari/iPhone: APIs no soportadas, PWA, viewport, botones, audio, compartir, copiar al portapapeles, localStorage y responsive.\nwhen_to_use: El usuario dice que en Safari no va, algo no se ve bien en iPhone, el audio no suena, no se copia, no detecta QR o la PWA falla en iOS.\nargument-hint: [síntoma en iPhone/Safari]\n---\n\n# Safari iOS Compat Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como auditor específico de Safari/iOS.\n\n## Revisión obligatoria\n1. APIs con soporte irregular: Clipboard, Share, Audio autoplay, Wake Lock, File System Access, Web Speech, Notifications.\n2. Eventos táctiles y teclado móvil.\n3. Viewport, safe areas, zoom involuntario en inputs, tamaño de botones.\n4. PWA iOS: iconos, `apple-touch-icon`, `theme-color`, instalación y service worker.\n5. Audio: debe iniciarse tras interacción del usuario.\n6. QR/canvas: contraste, tamaño, margen y descarga/copia.\n7. Fallbacks visibles cuando una API no existe.\n\n## Salida\nEntrega:\n- Causa más probable.\n- APIs sospechosas.\n- Cambios por archivo.\n- Fallback recomendado.\n- Prueba manual en iPhone.\n", "skills/security-privacy-review/SKILL.md": "---\nname: Security Privacy Review\ndescription: Revisa privacidad y seguridad en apps locales, formularios, localStorage, claves API, datos sensibles, XSS, dependencias y exposición accidental.\nwhen_to_use: El usuario pregunta por seguridad, datos sensibles, API keys, apps con login, formularios, localStorage, privacidad, GitHub público o uso por gente mayor.\nargument-hint: [objetivo opcional]\n---\n\n# Security Privacy Review\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como revisor de seguridad pragmático para apps locales, PWAs y proyectos frontend.\n\n## Revisión mínima\n1. Datos sensibles:\n   - ¿Se guardan en localStorage/sessionStorage?\n   - ¿Se exponen en HTML, JS o logs?\n   - ¿Hay datos médicos, contactos, ubicación o emergencias?\n2. API keys:\n   - No deben estar hardcodeadas en frontend público.\n   - Si cada usuario pone su clave, debe poder verla, cambiarla, borrarla y saber dónde se guarda.\n3. XSS e inyección:\n   - Evitar `innerHTML` con entrada de usuario.\n   - Sanitizar contenido o usar `textContent`.\n4. Red:\n   - Confirmar si la app envía datos fuera.\n   - Informar claramente al usuario.\n5. Dependencias:\n   - Evitar CDNs innecesarios si la app promete offline.\n6. GitHub público:\n   - No incluir claves, datos reales, zips innecesarios ni backups.\n7. Emergencias/personas mayores:\n   - No prometer sustitución de servicios de emergencia.\n   - Añadir confirmaciones, contactos fiables y mensajes claros.\n\n## Salida\nClasifica cada riesgo:\n- Crítico: exposición real de claves/datos o función peligrosa.\n- Alto: datos sensibles sin aviso o sin borrado.\n- Medio: malas prácticas mitigables.\n- Bajo: mejoras de transparencia.\n\nIncluye cambios concretos de código o texto legal si procede.\n", "skills/systematic-debugger/SKILL.md": "---\nname: Systematic Debugger\ndescription: Depura errores de forma sistemática: reproducir, aislar causa raíz, corregir, probar y evitar arreglos a ciegas.\nwhen_to_use: El usuario dice que algo no funciona, se queda parado, crashea, no responde, falla en Safari, no detecta QR, no arranca, o pide revisar un bug concreto.\nargument-hint: [objetivo opcional]\n---\n\n# Systematic Debugger\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como depurador sistemático. No improvises parches hasta entender el fallo.\n\n## Proceso obligatorio\n1. Define el síntoma exacto.\n2. Localiza el flujo que falla.\n3. Busca el archivo y la función responsables.\n4. Formula una hipótesis de causa raíz.\n5. Verifica si la hipótesis encaja con el código.\n6. Aplica el cambio mínimo que corrige la causa, no el síntoma.\n7. Revisa efectos secundarios.\n8. Propón una prueba manual reproducible.\n\n## Antipatrones prohibidos\n- Cambiar muchos archivos sin justificarlo.\n- Añadir una librería para tapar un bug simple.\n- Reiniciar estados sin explicar por qué.\n- Culpar al navegador sin revisar eventos, listeners, promesas y errores.\n- Decir “limpia caché” como única solución.\n\n## Cuando sea una app de chat local\nComprueba especialmente:\n- Estado `isTyping`, `isBusy` o similar.\n- Listeners duplicados.\n- Promesas sin `finally`.\n- Bloqueos tras la primera respuesta.\n- Historial mal actualizado.\n- Errores silenciosos en `try/catch`.\n\n## Salida\nEntrega:\n- Causa probable.\n- Archivo afectado.\n- Cambio exacto.\n- Prueba para confirmar.\n- Riesgo de regresión.\n\n\n## Evidencia mínima antes del veredicto\nAntes de decir que algo está listo, intenta obtener evidencia del proyecto real: estructura de archivos, puntos de entrada, errores visibles, flujo principal y pruebas reproducibles. Si no puedes ejecutar o abrir la app, dilo como limitación y da una checklist manual.\n", "skills/test-plan-generator/SKILL.md": "---\nname: Test Plan Generator\ndescription: Genera un plan de pruebas manuales y técnicas para apps web/locales antes de declararlas versión final.\nwhen_to_use: El usuario pregunta si una app está perfecta, lista para GitHub, sin bugs, o necesita pruebas de flujo, móvil, consola, seguridad y PWA.\nargument-hint: [tipo de app]\n---\n\n# Test Plan Generator\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como QA tester pragmático.\n\n## Plan mínimo\n1. Smoke test: abrir app, cargar assets, consola limpia.\n2. Flujo principal repetido 3 veces.\n3. Inputs vacíos, extremos y caracteres raros.\n4. Persistencia: guardar, recargar, borrar.\n5. Responsive: móvil estrecho, tablet y escritorio.\n6. Safari/iPhone si aplica.\n7. Offline/PWA si aplica.\n8. Accesibilidad básica: teclado, foco, contraste, labels.\n9. Seguridad: XSS simple, claves, datos locales.\n10. Release: README, LICENSE, rutas relativas.\n\n## Salida\nEntrega una tabla con:\n- ID de prueba.\n- Qué probar.\n- Pasos.\n- Resultado esperado.\n- Estado: pendiente/pasa/falla.\n- Prioridad.\n", "skills/ui-ux-mobile-auditor/SKILL.md": "---\nname: UI UX Mobile Auditor\ndescription: Audita interfaz, experiencia móvil, responsive, accesibilidad básica, legibilidad, jerarquía visual y microcopy.\nwhen_to_use: El usuario enseña capturas, dice que algo se ve raro, descuadrado, no queda bien, tapa elementos, no se ve en Safari/iPhone o pide diseño más profesional.\nargument-hint: [objetivo opcional]\n---\n\n# UI UX Mobile Auditor\n\n## Tarea recibida\n$ARGUMENTS\n\n\nActúa como diseñador UX/UI senior con criterio móvil-first.\n\n## Revisión\n1. Jerarquía visual:\n   - Título claro.\n   - Acción principal evidente.\n   - Secundarios sin competir.\n2. Responsive:\n   - Sin desbordes horizontales.\n   - Botones táctiles de al menos 44px.\n   - Espaciado cómodo.\n   - Formularios legibles en móvil.\n3. Accesibilidad:\n   - Contraste suficiente.\n   - Labels visibles o accesibles.\n   - Foco de teclado.\n   - Texto no minúsculo en exceso.\n4. Estado de la app:\n   - Loading, vacío, error, éxito.\n   - Feedback inmediato tras pulsar.\n5. Microcopy:\n   - Quitar frases técnicas internas.\n   - Evitar claims falsos.\n   - Explicar acciones críticas.\n6. Estética:\n   - Coherencia de color, sombras, iconos, borde y tono.\n\n## Salida\nDa:\n- Diagnóstico visual.\n- 5 mejoras de mayor impacto.\n- CSS/HTML recomendado si procede.\n- Checklist de prueba en móvil.\n", "skills/zip-release-builder/SKILL.md": "---\nname: ZIP Release Builder\ndescription: Prepara un ZIP final limpio para publicar: estructura, nombres, exclusiones, README, versión, changelog y validación básica.\nwhen_to_use: Úsalo cuando el usuario quiere “devuélvemelo listo para GitHub”, “empaquetado final” o “versión definitiva”.\nargument-hint: [nombre del release]\n---\n\n# ZIP Release Builder\n\n## Tarea recibida\n$ARGUMENTS\n\nActúa como responsable de empaquetado de release.\n\n## Proceso\n1. Define carpeta raíz limpia con nombre y versión.\n2. Incluye solo archivos necesarios.\n3. Excluye: `.git`, `node_modules`, logs, backups, capturas privadas, zips antiguos, archivos temporales.\n4. Verifica `README`, `LICENSE`, `CHANGELOG`, `.gitignore` y estructura.\n5. Sincroniza versión en archivos relevantes.\n6. Añade checklist de publicación.\n7. Genera nombre de ZIP claro.\n\n## Salida\nEntrega:\n- Árbol de archivos final.\n- Archivos excluidos.\n- Nombre del ZIP.\n- Comandos Git sugeridos.\n- Prueba mínima antes de publicar.\n", "skills-manifest.json": "{\n  \"name\": \"i-roig-claude-skills-pack\",\n  \"version\": \"1.3.2\",\n  \"description\": \"33 Skills para Claude/Claude Code: apps GitHub, PWA, seguridad, debugging, prompts, IA local, narrativa, KDP, testing y despliegue.\",\n  \"skills\": [\n    \"accessibility-basic-auditor\",\n    \"ai-feature-designer\",\n    \"ai-integration-planner\",\n    \"api-key-safety-planner\",\n    \"app-product-polisher\",\n    \"brand-voice-dark\",\n    \"browser-compatibility-auditor\",\n    \"claude-skill-builder\",\n    \"codebase-context-loader\",\n    \"console-error-hunter\",\n    \"dark-landing-page-writer\",\n    \"fiction-world-bible-builder\",\n    \"github-app-auditor\",\n    \"github-pages-deploy-check\",\n    \"github-pages-path-fixer\",\n    \"kdp-launch-checklist\",\n    \"local-first-architecture\",\n    \"local-storage-data-auditor\",\n    \"loop-engineering-agent\",\n    \"mobile-touch-auditor\",\n    \"no-dependency-auditor\",\n    \"novelist-editor-hard\",\n    \"ollama-local-planner\",\n    \"prompt-optimizer-claude\",\n    \"pwa-offline-auditor\",\n    \"readme-github-pro\",\n    \"release-finalizer\",\n    \"safari-ios-compat-auditor\",\n    \"security-privacy-review\",\n    \"systematic-debugger\",\n    \"test-plan-generator\",\n    \"ui-ux-mobile-auditor\",\n    \"zip-release-builder\"\n  ],\n  \"author\": \"I. Roig\",\n  \"repository\": \"https://github.com/tu-usuario/i-roig-claude-skills-pack\",\n  \"license\": \"MIT\",\n  \"minimum_structure\": {\n    \"skill_entrypoint\": \"SKILL.md\",\n    \"personal_install_path\": \"~/.claude/skills\",\n    \"project_install_path\": \".claude/skills\"\n  }\n}\n", "templates/README-APP-LOCAL.md": "# Nombre de la app\n\nDescripción breve: qué hace, para quién sirve y si funciona offline.\n\n## Funciones\n- Función principal 1\n- Función principal 2\n- Privacidad/offline si aplica\n\n## Uso local\n1. Descarga el proyecto.\n2. Abre `index.html` o ejecuta el comando indicado.\n3. Usa la app desde el navegador.\n\n## GitHub Pages\nActiva Pages desde Settings → Pages y selecciona la rama/carpeta correspondiente.\n\n## Privacidad\nExplica qué datos se guardan, dónde se guardan y cómo borrarlos.\n\n## Estructura\n```text\nindex.html\nstyle.css\napp.js\nmanifest.json\nsw.js\n```\n\n## Licencia\nMIT u otra licencia elegida.\n"};
const VERSION = '1.3.2-web';

const $ = (sel, root = document) => root.querySelector(sel);
const $$ = (sel, root = document) => [...root.querySelectorAll(sel)];

const state = {
  query: '',
  category: 'all',
  view: 'all',
  filter: 'all',
  favorites: new Set(JSON.parse(localStorage.getItem('iroig.skillFavorites') || '[]')),
  checklist: JSON.parse(localStorage.getItem('iroig.releaseChecklist') || '{}'),
};

const releaseItems = [
  'El proyecto abre con index.html y también desde servidor local.',
  'No hay errores rojos en consola al cargar ni al usar el flujo principal.',
  'Las rutas funcionan en GitHub Pages, incluso dentro de subcarpeta.',
  'La app responde bien en móvil, tablet y escritorio.',
  'Los botones principales tienen estado visible y no se quedan bloqueados.',
  'localStorage no guarda datos sensibles sin aviso claro.',
  'README.md explica instalación, uso, estructura y despliegue.',
  'LICENSE, SECURITY, CHANGELOG y .gitignore están presentes.',
  'El service worker no cachea una versión rota ni rompe Safari/iPhone.',
  'La versión final no contiene textos de prueba, etiquetas raras ni mensajes internos.'
];

function init() {
  $('#statSkills').textContent = SKILLS.length;
  restoreTheme();
  buildCategorySelect();
  buildQuickFilters();
  renderSkills();
  renderChecklist();
  bindEvents();
  restoreNotes();
  setupPwa();
  setStatus(`${SKILLS.length} Skills cargadas`);
}

function bindEvents() {
  $('#searchInput').addEventListener('input', e => { state.query = e.target.value.trim().toLowerCase(); renderSkills(); });
  $('#categorySelect').addEventListener('change', e => { state.category = e.target.value; renderSkills(); });
  $('#viewSelect').addEventListener('change', e => { state.view = e.target.value; renderSkills(); });
  $('#themeBtn').addEventListener('click', toggleTheme);
  $('#downloadPackBtn').addEventListener('click', downloadGeneratedPack);
  $('#copyInstallBtn').addEventListener('click', () => copyText('./install-windows.ps1', 'Comando de instalación copiado'));
  $('#buildWorkflowBtn').addEventListener('click', buildWorkflow);
  $('#copyWorkflowBtn').addEventListener('click', () => copyText($('#workflowOutput').textContent, 'Flujo copiado'));
  $('#closeDialogBtn').addEventListener('click', () => $('#skillDialog').close());
  $('#skillDialog').addEventListener('click', e => { if (e.target.id === 'skillDialog') e.currentTarget.close(); });
  $('#resetChecklistBtn').addEventListener('click', () => { state.checklist = {}; persistChecklist(); renderChecklist(); toast('Checklist reiniciado'); });
  $('#notesInput').addEventListener('input', e => localStorage.setItem('iroig.notes', e.target.value));
  $$('.copy-static').forEach(btn => btn.addEventListener('click', () => copyText(btn.dataset.copy, 'Comando copiado')));
}

function restoreTheme() {
  const saved = localStorage.getItem('iroig.theme');
  const prefersLight = matchMedia('(prefers-color-scheme: light)').matches;
  document.documentElement.dataset.theme = saved || (prefersLight ? 'light' : 'dark');
}
function toggleTheme() {
  const next = document.documentElement.dataset.theme === 'light' ? 'dark' : 'light';
  document.documentElement.dataset.theme = next;
  localStorage.setItem('iroig.theme', next);
  toast(next === 'dark' ? 'Modo oscuro activado' : 'Modo claro activado');
}

function buildCategorySelect() {
  const select = $('#categorySelect');
  select.innerHTML = '<option value="all">Todas</option>' + CATEGORIES.map(c => `<option value="${escapeAttr(c)}">${escapeHtml(c)}</option>`).join('');
}

function buildQuickFilters() {
  const filters = ['all', 'github', 'safari', 'seguridad', 'pwa', 'ia', 'local', 'novela', 'kdp', 'debugging'];
  $('#quickFilters').innerHTML = filters.map(f => `<button type="button" data-filter="${f}" class="${f === 'all' ? 'active' : ''}">${f === 'all' ? 'Todo' : f}</button>`).join('');
  $$('#quickFilters button').forEach(btn => btn.addEventListener('click', () => {
    state.filter = btn.dataset.filter;
    $$('#quickFilters button').forEach(b => b.classList.toggle('active', b === btn));
    renderSkills();
  }));
}

function skillMatches(skill) {
  const text = [skill.slug, skill.name, skill.category, skill.description, skill.whenToUse, skill.useCase, ...skill.tags].join(' ').toLowerCase();
  const matchesQuery = !state.query || text.includes(state.query);
  const matchesCategory = state.category === 'all' || skill.category === state.category;
  const matchesView = state.view === 'all' || (state.view === 'favorites' && state.favorites.has(skill.slug)) || (state.view === 'high' && skill.priority === 'Alta');
  const matchesFilter = state.filter === 'all' || text.includes(state.filter);
  return matchesQuery && matchesCategory && matchesView && matchesFilter;
}

function renderSkills() {
  const visible = SKILLS.filter(skillMatches);
  $('#miniStatus').textContent = `${visible.length} de ${SKILLS.length}`;
  if (!visible.length) {
    $('#skillsGrid').innerHTML = '<div class="empty">No hay Skills con esos filtros. Prueba con “GitHub”, “Safari”, “seguridad” o limpia la búsqueda.</div>';
    return;
  }
  $('#skillsGrid').innerHTML = visible.map(skill => `
    <article class="skill-card" data-slug="${escapeAttr(skill.slug)}">
      <div class="skill-top">
        <span class="badge">${escapeHtml(skill.category)}</span>
        <button class="icon-btn fav-btn" type="button" aria-label="Favorita" data-fav="${escapeAttr(skill.slug)}">${state.favorites.has(skill.slug) ? '★' : '☆'}</button>
      </div>
      <div>
        <h3>${escapeHtml(skill.name)}</h3>
        <p>${escapeHtml(skill.description)}</p>
      </div>
      <span class="badge priority">Prioridad ${escapeHtml(skill.priority)}</span>
      <div class="tags">${skill.tags.slice(0,4).map(t => `<span>${escapeHtml(t)}</span>`).join('')}</div>
      <div class="card-actions">
        <button class="secondary open-skill" type="button" data-open="${escapeAttr(skill.slug)}">Abrir</button>
        <button class="ghost copy-command" type="button" data-command="${escapeAttr(skill.command)}">Copiar comando</button>
      </div>
    </article>
  `).join('');
  $$('.open-skill').forEach(btn => btn.addEventListener('click', () => openSkill(btn.dataset.open)));
  $$('.copy-command').forEach(btn => btn.addEventListener('click', () => copyText(`${btn.dataset.command} `, 'Comando copiado')));
  $$('.fav-btn').forEach(btn => btn.addEventListener('click', e => { e.stopPropagation(); toggleFavorite(btn.dataset.fav); }));
}

function toggleFavorite(slug) {
  if (state.favorites.has(slug)) state.favorites.delete(slug); else state.favorites.add(slug);
  localStorage.setItem('iroig.skillFavorites', JSON.stringify([...state.favorites]));
  renderSkills();
}

function openSkill(slug) {
  const skill = SKILLS.find(s => s.slug === slug);
  if (!skill) return;
  $('#dialogContent').innerHTML = `
    <section class="dialog-hero">
      <span class="badge">${escapeHtml(skill.category)}</span>
      <h2>${escapeHtml(skill.name)}</h2>
      <p class="muted">${escapeHtml(skill.description)}</p>
      <div class="dialog-actions">
        <button class="primary" id="copySkillCommand" type="button">Copiar comando</button>
        <button class="secondary" id="copySkillPrompt" type="button">Copiar prompt base</button>
        <button class="ghost" id="downloadSkillMd" type="button">Descargar SKILL.md</button>
        <button class="ghost" id="favoriteDialog" type="button">${state.favorites.has(skill.slug) ? 'Quitar favorita' : 'Marcar favorita'}</button>
      </div>
    </section>
    <section class="dialog-body">
      <h3>Cuándo usarla</h3>
      <p class="muted">${escapeHtml(skill.useCase || skill.whenToUse)}</p>
      <h3>Ejemplo rápido</h3>
      <div class="terminal"><pre>${escapeHtml(skill.example)}</pre></div>
      <h3>Contenido de la Skill</h3>
      <pre class="raw-skill">${escapeHtml(skill.content)}</pre>
    </section>
  `;
  $('#copySkillCommand').addEventListener('click', () => copyText(`${skill.command} `, 'Comando copiado'));
  $('#copySkillPrompt').addEventListener('click', () => copyText(skill.example, 'Prompt copiado'));
  $('#downloadSkillMd').addEventListener('click', () => downloadText(`SKILL-${skill.slug}.md`, skill.content));
  $('#favoriteDialog').addEventListener('click', () => { toggleFavorite(skill.slug); openSkill(slug); });
  $('#skillDialog').showModal();
}

function buildWorkflow() {
  const type = $('#projectType').value;
  const goal = $('#workflowGoal').value.trim() || 'dejarlo listo con criterio profesional';
  const map = {
    html: ['/codebase-context-loader Primero entiende este repo.', `/github-app-auditor Revisa esta app y dime si está lista para ${goal}.`, '/github-pages-deploy-check Comprueba rutas, assets y compatibilidad con GitHub Pages.', '/test-plan-generator Crea pruebas manuales finales.', '/release-finalizer Limpia el proyecto y déjalo como release candidate.'],
    pwa: ['/codebase-context-loader Primero entiende estructura y flujo principal.', `/pwa-offline-auditor Revisa manifest, sw.js, caché y modo offline para ${goal}.`, '/safari-ios-compat-auditor Comprueba riesgos en iPhone/Safari.', '/security-privacy-review Revisa datos locales y privacidad.', '/release-finalizer Prepara la versión final.'],
    bug: ['/systematic-debugger Reproduce, aísla y corrige la causa raíz del fallo.', '/test-plan-generator Crea prueba de regresión para confirmar que no vuelve.', '/github-app-auditor Revisa efectos secundarios generales.'],
    safari: ['/safari-ios-compat-auditor Revisa por qué falla en iPhone/Safari.', '/systematic-debugger Localiza la causa raíz sin parches a ciegas.', '/pwa-offline-auditor Comprueba si el service worker/cache interviene.', '/test-plan-generator Crea pruebas para Safari, iOS y Chrome.'],
    ai: ['/ai-feature-designer Decide si esta app necesita IA real, motor local u Ollama.', '/api-key-safety-planner Diseña manejo seguro de claves API.', '/ai-integration-planner Diseña integración sin exponer claves del usuario.', '/security-privacy-review Revisa API keys, localStorage, permisos y privacidad.', '/release-finalizer Prepara release limpio.'],
    localfirst: ['/local-first-architecture Diseña la app como local-first/offline.', '/no-dependency-auditor Comprueba que no depende de CDNs ni recursos externos.', '/local-storage-data-auditor Revisa persistencia, exportación y borrado.', '/test-plan-generator Crea pruebas finales offline.'],
    kdp: ['/kdp-launch-checklist Revisa si el libro está listo para publicar en KDP.', '/brand-voice-dark Ajusta descripción y copy con voz oscura elegante.', '/prompt-optimizer-claude Convierte mejoras en instrucciones claras.'],
    novel: ['/fiction-world-bible-builder Construye o revisa la biblia narrativa.', '/novelist-editor-hard Revisa capítulo, ritmo, tensión, diálogos y prosa sin complacencia.', '/brand-voice-dark Mantén identidad oscura y voz propia.', '/prompt-optimizer-claude Convierte las mejoras en instrucciones claras para continuar.']
  };
  $('#workflowOutput').textContent = (map[type] || map.html).join('\n');
  toast('Flujo creado');
}

function renderChecklist() {
  $('#releaseChecklist').innerHTML = releaseItems.map((item, i) => `
    <label class="check-item">
      <input type="checkbox" data-check="${i}" ${state.checklist[i] ? 'checked' : ''} />
      <span>${escapeHtml(item)}</span>
    </label>
  `).join('');
  $$('#releaseChecklist input').forEach(input => input.addEventListener('change', () => {
    state.checklist[input.dataset.check] = input.checked;
    persistChecklist();
  }));
}
function persistChecklist() { localStorage.setItem('iroig.releaseChecklist', JSON.stringify(state.checklist)); }

function restoreNotes() { $('#notesInput').value = localStorage.getItem('iroig.notes') || ''; }

function copyText(text, message = 'Copiado') {
  if (navigator.clipboard && window.isSecureContext) {
    navigator.clipboard.writeText(text).then(() => toast(message)).catch(() => fallbackCopy(text, message));
  } else fallbackCopy(text, message);
}
function fallbackCopy(text, message) {
  const ta = document.createElement('textarea'); ta.value = text; document.body.appendChild(ta); ta.select(); document.execCommand('copy'); ta.remove(); toast(message);
}
function downloadText(filename, text) {
  const blob = new Blob([text], { type: 'text/markdown;charset=utf-8' });
  downloadBlob(filename, blob);
}
function downloadBlob(filename, blob) {
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob); a.download = filename; document.body.appendChild(a); a.click();
  setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 800);
}

function downloadGeneratedPack() {
  const files = { ...PACK_FILES };
  files['README-WEB-DOWNLOAD.txt'] = `I. Roig Claude Skills Pack\nGenerado desde la app web offline.\nSkills incluidas: ${SKILLS.length}\nVersión web: ${VERSION}\n`;
  const blob = makeZip(files);
  downloadBlob('i-roig-claude-skills-pack-generado.zip', blob);
  toast('ZIP generado en el navegador');
}

// Minimal ZIP writer, no dependencies. Store method only.
function makeZip(files) {
  const encoder = new TextEncoder();
  const entries = [];
  let offset = 0;
  const chunks = [];
  for (const [name, content] of Object.entries(files)) {
    const nameBytes = encoder.encode(name);
    const data = encoder.encode(content);
    const crc = crc32(data);
    const local = new Uint8Array(30 + nameBytes.length);
    const v = new DataView(local.buffer);
    v.setUint32(0, 0x04034b50, true); v.setUint16(4, 20, true); v.setUint16(6, 0, true); v.setUint16(8, 0, true);
    v.setUint16(10, dosTime(), true); v.setUint16(12, dosDate(), true); v.setUint32(14, crc, true);
    v.setUint32(18, data.length, true); v.setUint32(22, data.length, true); v.setUint16(26, nameBytes.length, true); v.setUint16(28, 0, true);
    local.set(nameBytes, 30);
    chunks.push(local, data);
    entries.push({ nameBytes, crc, size: data.length, offset });
    offset += local.length + data.length;
  }
  const centralStart = offset;
  for (const e of entries) {
    const central = new Uint8Array(46 + e.nameBytes.length);
    const v = new DataView(central.buffer);
    v.setUint32(0, 0x02014b50, true); v.setUint16(4, 20, true); v.setUint16(6, 20, true); v.setUint16(8, 0, true); v.setUint16(10, 0, true);
    v.setUint16(12, dosTime(), true); v.setUint16(14, dosDate(), true); v.setUint32(16, e.crc, true);
    v.setUint32(20, e.size, true); v.setUint32(24, e.size, true); v.setUint16(28, e.nameBytes.length, true);
    v.setUint16(30, 0, true); v.setUint16(32, 0, true); v.setUint16(34, 0, true); v.setUint16(36, 0, true);
    v.setUint32(38, 0, true); v.setUint32(42, e.offset, true);
    central.set(e.nameBytes, 46);
    chunks.push(central); offset += central.length;
  }
  const centralSize = offset - centralStart;
  const end = new Uint8Array(22);
  const v = new DataView(end.buffer);
  v.setUint32(0, 0x06054b50, true); v.setUint16(4, 0, true); v.setUint16(6, 0, true);
  v.setUint16(8, entries.length, true); v.setUint16(10, entries.length, true); v.setUint32(12, centralSize, true); v.setUint32(16, centralStart, true); v.setUint16(20, 0, true);
  chunks.push(end);
  return new Blob(chunks, { type: 'application/zip' });
}
function dosTime(d = new Date()) { return (d.getHours() << 11) | (d.getMinutes() << 5) | Math.floor(d.getSeconds() / 2); }
function dosDate(d = new Date()) { return ((d.getFullYear() - 1980) << 9) | ((d.getMonth() + 1) << 5) | d.getDate(); }
function crc32(data) {
  let c = ~0;
  for (let i = 0; i < data.length; i++) {
    c ^= data[i];
    for (let k = 0; k < 8; k++) c = (c >>> 1) ^ (0xedb88320 & -(c & 1));
  }
  return (~c) >>> 0;
}

let deferredPrompt;
function setupPwa() {
  window.addEventListener('beforeinstallprompt', e => { e.preventDefault(); deferredPrompt = e; $('#installPwaBtn').hidden = false; });
  $('#installPwaBtn').addEventListener('click', async () => { if (!deferredPrompt) return; deferredPrompt.prompt(); await deferredPrompt.userChoice; deferredPrompt = null; $('#installPwaBtn').hidden = true; });
  if ('serviceWorker' in navigator && location.protocol !== 'file:') {
    navigator.serviceWorker.register('./sw.js').catch(() => {});
  }
}

function setStatus(msg) { $('#miniStatus').textContent = msg; }
function toast(msg) { const t = $('#toast'); t.textContent = msg; t.classList.add('show'); clearTimeout(window.__toastTimer); window.__toastTimer = setTimeout(() => t.classList.remove('show'), 1800); }
function escapeHtml(str='') { return String(str).replace(/[&<>"']/g, m => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m])); }
function escapeAttr(str='') { return escapeHtml(str).replace(/`/g, '&#096;'); }

document.addEventListener('DOMContentLoaded', init);
